import json
import logging
import os
import io
from pathlib import Path

MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MB

logger = logging.getLogger(__name__)


class CandidatesFileError(Exception):
    """Raised when the candidates file cannot be loaded or is invalid."""


def load_candidates_file(candidates_file: str) -> dict:
    base_dir = Path.cwd()
    try:
        abs_path = Path(candidates_file).resolve(strict=True)
    except FileNotFoundError as exc:
        logger.error("Candidates file does not exist: %s", candidates_file, exc_info=exc)
        raise CandidatesFileError(f"File not found: {candidates_file}") from exc

    try:
        abs_path.relative_to(base_dir)
    except ValueError:
        safe_name = abs_path.name
        logger.warning("Attempted to access file outside allowed directory: %s", safe_name)
        raise CandidatesFileError("Invalid file location.") from None

    try:
        with abs_path.open("rb") as f:
            file_size = os.fstat(f.fileno()).st_size
            if file_size > MAX_FILE_SIZE:
                logger.error(
                    "Candidates file size %d exceeds maximum allowed %d",
                    file_size,
                    MAX_FILE_SIZE,
                )
                raise CandidatesFileError("File size too large.")
            try:
                text_wrapper = io.TextIOWrapper(f, encoding="utf-8")
                data = json.load(text_wrapper)
            except (OSError, json.JSONDecodeError) as exc:
                logger.error("Failed to parse candidates file", exc_info=exc)
                raise CandidatesFileError("Failed to parse JSON.") from exc
    except OSError as exc:
        logger.error("Failed to read candidates file", exc_info=exc)
        raise CandidatesFileError("Unable to read file.") from exc

    if not isinstance(data, dict):
        logger.error("Candidates file does not contain a dictionary")
        raise CandidatesFileError("Root element must be a dictionary")

    return data


def test_fixed_size_set_generator(
