):
    candidates = load_candidates_file(candidates_file)

    required_keys = {"test_key_1", "test_key_2"}
    missing_keys = required_keys - set(candidates.keys())
    if missing_keys:
        logger.warning("Missing keys in candidates: %s", missing_keys)
        pytest.fail("Missing keys in candidates.")

    try:
        result = fixed_size_set_generator(random, args, candidates)
    except Exception as exc:
        logger.error("fixed_size_set_generator raised an exception", exc_info=exc)
        pytest.fail("fixed_size_set_generator raised an exception.")

    if not isinstance(result, dict):
