import os
import re
import mimetypes
from urllib.parse import unquote

BASE_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), "static"))
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MB
ALLOWED_MIME_TYPES = {
    "text/html",
    "text/css",
    "application/javascript",
    "application/json",
    "image/png",
    "image/jpeg",
    "image/gif",
    "text/plain",
}
HEADER_NAME_PATTERN = re.compile(r"^[A-Za-z0-9!#$%&'*+.\-^_`|~]+$")

def safe_full_path(request_path: str) -> str | None:
    if len(request_path) > 2048:
        return None
    try:
        decoded = unquote(request_path)
        decoded = unquote(decoded)  # doubleâdecode to catch doubleâencoding bypass
    except Exception:
        return None

    path_norm = decoded.replace("\", "/")
    path_norm = os.path.normpath(path_norm).lstrip("/")
    if path_norm == "" or ".." in path_norm.split("/"):
        return None

    candidate = os.path.join(BASE_DIR, path_norm)
    real = os.path.realpath(candidate)
    if os.path.commonpath([BASE_DIR, real]) != BASE_DIR:
        return None
    return real

def validate_header(name: str, value: str) -> tuple[str, str] | None:
    if not HEADER_NAME_PATTERN.fullmatch(name):
        return None
    if re.search(r"[�--]", value):
        return None
    if "" in value or "
" in value:
        return None
    return name, value

def serve_static(req, start_response):
    path = req.path
    full_path = safe_full_path(path)
    if full_path is None:
        start_response("403 Forbidden", [("Content-Type", "text/plain")])
        return [b"Forbidden"]

    if os.path.isdir(full_path):
        full_path = os.path.join(full_path, "index.html")

    try:
        size = os.path.getsize(full_path)
    except OSError:
        start_response("404 Not Found", [("Content-Type", "text/plain")])
        return [b"Not Found"]

    if size > MAX_FILE_SIZE:
        start_response("413 Payload Too Large", [("Content-Type", "text/plain")])
        return [b"File Too Large"]

    mime_type, _ = mimetypes.guess_type(full_path)
    if mime_type:
        mime_type = mime_type.split(";")[0].strip()
    if mime_type not in ALLOWED_MIME_TYPES:
        mime_type = "application/octet-stream"

    safe_headers = []
    for name, value in req.headers.items():
        sanitized = validate_header(name, value)
        if sanitized:
            safe_headers.append(sanitized)

    response_headers = safe_headers + [
        ("Content-Type", mime_type),
        ("Content-Length", str(size)),
        ("X-Content-Type-Options", "nosniff"),
    ]

    start_response("200 OK", response_headers)

    def file_iterator():
        f = open(full_path, "rb")
        try:
            while True:
                chunk = f.read(8192)
                if not chunk:
                    break
                yield chunk
        finally:
            f.close()

    return file_iterator()

