from pathlib import Path

class TurqTestInstance:
    _ALLOWED_BINARIES = {Path("/usr/local/bin/turq").resolve()}

    def __init__(self, host: str = "localhost", mock_port: int = 13095, editor_port: int = 13096):
        self.host = host
        self.mock_port = mock_port
        self.editor_port = editor_port

        self._validate_host()
        self._validate_ports()

        self.turq_path = self._resolve_turq_binary()
        self.turq_process = None
        self._start_process()

    def _validate_host(self) -> None:
        try:
            addr_info = socket.getaddrinfo(self.host, None, socket.AF_UNSPEC, socket.SOCK_STREAM)
        except OSError as exc:
            raise ValueError(f"Unable to resolve host {self.host}") from exc
        if not any(
            ai[4][0].startswith("127.") or ai[4][0] == "::1" for ai in addr_info
        ):
            raise ValueError("host must resolve to a loopback address")

    def _validate_ports(self) -> None:
        for port in (self.mock_port, self.editor_port):
            if not isinstance(port, int) or not (0 < port < 65536):
                raise ValueError("Port numbers must be valid integers 1-65535")

    def _resolve_turq_binary(self) -> Path:
        env_path = os.getenv("TURQ_BINARY")
        candidate = Path(env_path).resolve() if env_path else Path("/usr/local/bin/turq").resolve()
        if candidate not in self._ALLOWED_BINARIES:
            raise ValueError("TURQ_BINARY is not a trusted binary path")
        if not (candidate.is_file() and os.access(candidate, os.X_OK)):
            raise FileNotFoundError(f"Turq binary not found or not executable: {candidate}")
        if candidate.stat().st_mode & 0o022:
            raise PermissionError(f"Binary {candidate} is group or world writable")
        return candidate

    def _start_process(self) -> None:
        cmd = [
            str(self.turq_path),
            "--host", self.host,
            "--port", str(self.mock_port),
            "--editor-port", str(self.editor_port),
        ]

        try:
            self.turq_process = subprocess.Popen(
                cmd,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                shell=False,
                preexec_fn=os.setsid if os.name == "posix" else None,
            )
        except OSError as exc:
            raise RuntimeError(f"Failed to start Turq process: {exc}") from exc

        timeout = 10
        end_time = time.time() + timeout
        while time.time() < end_time:
            try:
                with socket.create_connection((self.host, self.mock_port), timeout=1):
                    return
            except OSError:
                time.sleep(0.1)
        self._cleanup()
        raise TimeoutError("Turq did not start listening on the expected port in time")

    def _cleanup(self) -> None:
        proc = self.turq_process
        if proc is None:
            return
        if proc.poll() is None:
            try:
                proc.terminate()
                proc.wait(timeout=5)
            except Exception:
                pass
        self.turq_process = None

    def __enter__(self) -> "TurqTestInstance":
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> bool:
        self._cleanup()
        return False

    def __del__(self):
        self._cleanup()

