import logging
import tempfile
from pathlib import Path
from typing import Iterable, List, Tuple

logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO)

# Create a dedicated, unique temporary directory for safe operations with restrictive permissions
SAFE_BASE_DIR: Path = Path(tempfile.mkdtemp(prefix="safe_"))
# No need to mkdir again; the directory is already created with 0o700 permissions

# Resolve absolute paths for executables once
EXECUTABLES = {
    "echo": Path("/bin/echo").resolve(),
    "mkdir": Path("/bin/mkdir").resolve(),
    "touch": Path("/bin/touch").resolve(),
    "cat": Path("/bin/cat").resolve(),
    "grep": Path("/bin/grep").resolve(),
}
ALLOWED_COMMANDS = set(EXECUTABLES.keys())


def is_within_base(path: Path) -> bool:
    """
    Verify that a given path resides inside the safe base directory.
    """
    try:
        resolved = path.resolve(strict=True)
    except Exception:
        return False

    try:
        return resolved.is_relative_to(SAFE_BASE_DIR)
    except AttributeError:  # Python <3.9 compatibility
        return SAFE_BASE_DIR in resolved.parents


def safe_remove(path: Path) -> None:
    """
    Safely delete a file or empty directory within the safe base directory.
    """
    if not is_within_base(path):
        raise PermissionError(f"Attempted to remove file outside safe directory: {path}")
    if path.is_file():
        path.unlink()
    elif path.is_dir():
        path.rmdir()
    else:
        raise FileNotFoundError(f"No such file or directory: {path}")


def run_command_sequence(commands: Iterable[Tuple[str, List[str]]]) -> None:
    """
    Execute a sequence of allowed commands with strict validation.

    Each command is a tuple (name, args_list).
    """
    for entry in commands:
        try:
            if not isinstance(entry, (list, tuple)) or len(entry) != 2:
                raise ValueError(f"Command entry must be a twoâitem tuple: {entry}")

            name, args = entry

            # Basic type checks
            if not isinstance(name, str):
                raise TypeError("Command name must be a string")
            if not isinstance(args, list):
                raise TypeError("Command arguments must be provided as a list")
            if not name.isidentifier():
                raise ValueError(f"Invalid command name: {name!r}")
            if name not in ALLOWED_COMMANDS:
                raise ValueError(f"Command {name!r} not permitted")

            # Handle special 'rm' command safely
            if name == "rm":
                if len(args) != 1:
                    raise ValueError("rm requires exactly one argument")
                target = Path(args[0])
                safe_remove(target)
                logger.debug("Safely removed %s", target)
                continue

            # Validate fileâbased arguments
            resolved_args: List[str] = []
            for arg in args:
                if not isinstance(arg, str):
                    raise TypeError("Command arguments must be strings")
                if name in {"mkdir", "touch", "cat", "grep"}:
                    p = Path(arg)
                    if not is_within_base(p):
                        raise PermissionError(f"Disallowed file path: {arg}")
                    resolved_args.append(str(p))
                else:
                    resolved_args.append(arg)

            # Construct and run the subprocess command safely
            cmd = [str(EXECUTABLES[name])] + resolved_args
            result = subprocess.run(
                cmd,
                check=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                env={"PATH": "/usr/bin:/bin"},
            )
            logger.debug("Command %s succeeded: %s", name, result.stdout.strip())

        except Exception as exc:
            logger.exception("Failed to process command %s: %s", entry, exc)

