def parse_events(raw_text):
    """
    Parses event data from a raw string and returns a list of validated event dictionaries.
    Each event dictionary contains:
        x (int): X-coordinate, must be nonânegative
        y (int): Y-coordinate, must be nonânegative
        time (int): Timestamp, must be positive
        type (int): Event type, must be either 1 or 5
    Lines that cannot be parsed or do not meet validation criteria are skipped.
    """
    events = []

    if not isinstance(raw_text, str):
        return events

    try:
        lines = raw_text.splitlines()
    except Exception:
        return events

    if len(lines) < 2:
        return events

    try:
        split_objects = lines[1].splitlines()
    except Exception:
        return events

    for line in split_objects:
        if not line.strip():
            continue
        try:
            params = [p.strip() for p in line.split(",")]
            if len(params) < 4:
                continue
            posx = int(params[0])
            posy = int(params[1])
            timestamp = int(params[2])
            ntype = int(params[3])
        except (ValueError, IndexError):
            continue

        if posx < 0 or posy < 0 or timestamp <= 0:
            continue
        if ntype not in (1, 5):
            continue

        events.append({"x": posx, "y": posy, "time": timestamp, "type": ntype})

    return events

