from stat import S_ISREG
from typing import Optional

def read_last_non_empty_line(msg_path: str, msg_file_name: str) -> str:
    """Read the last nonâempty line of a file safely within msg_path."""
    base_dir = pathlib.Path(msg_path).resolve(strict=True)

    candidate_path = base_dir / msg_file_name
    try:
        resolved_path = candidate_path.resolve(strict=True)
    except FileNotFoundError as exc:
        raise FileNotFoundError("Message file not found") from exc

    if not resolved_path.is_relative_to(base_dir):
        raise ValueError("Resolved path escapes the base directory")

    if not resolved_path.is_file():
        raise FileNotFoundError("Message file not found")

    flags = os.O_RDONLY | os.O_CLOEXEC
    if not hasattr(os, "O_NOFOLLOW"):
        raise RuntimeError("O_NOFOLLOW flag not supported on this platform")
    flags |= os.O_NOFOLLOW

    try:
        fd = os.open(str(resolved_path), flags)
    except OSError as exc:
        raise RuntimeError("Failed to open the message file") from exc

    fd_closed = False
    try:
        stat_info = os.fstat(fd)
        if not S_ISREG(stat_info.st_mode):
            raise RuntimeError("Target is not a regular file")

        with os.fdopen(fd, "r", encoding="utf-8", newline="") as fh:
            fd_closed = True
            last_line: Optional[str] = None
            for line in fh:
                stripped = line.rstrip("
")
                if stripped:
                    last_line = stripped
            if last_line is None:
                raise ValueError("The message file is empty")
            return last_line
    finally:
        if not fd_closed:
            os.close(fd)

