logger = logging.getLogger(__name__)

def is_valid_username(name: str) -> bool:
    """
    Validate GitHub username: 1-39 chars, alphanumerics, hyphens or underscores,
    cannot start or end with hyphen/underscore, and no consecutive hyphens or underscores.
    """
    pattern = (
        r"^[A-Za-z0-9](?:[A-Za-z0-9]|(?:(?<![-_])[-_](?=[A-Za-z0-9]))){0,38}$"
    )
    return bool(re.fullmatch(pattern, name))

class GitHubFetcher:
    """
    Fetch public repositories for a valid GitHub user.
    """
    API_URL_TEMPLATE = "https://api.github.com/users/{user}/repos"
    USER_AGENT = "SecureFetch/1.0 (+https://example.com)"

    def __init__(self, user: str, timeout: float = 5.0, max_retries: int = 3):
        self.user = user
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({"User-Agent": self.USER_AGENT})
        retries = Retry(
            total=max_retries,
            backoff_factor=0.5,
            status_forcelist=[429, 500, 502, 503, 504],
            allowed_methods=["GET"]
        )
        self.session.mount("https://", HTTPAdapter(max_retries=retries))

    def get_repos(self) -> List[Dict[str, Any]]:
        url = self.API_URL_TEMPLATE.format(user=self.user)
        try:
            response = self.session.get(url, timeout=self.timeout)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.HTTPError as http_err:
            logger.warning("HTTP error for user %s: %s", self.user, http_err)
        except requests.exceptions.RequestException as req_err:
            logger.warning("Request error for user %s: %s", self.user, req_err)
        except ValueError as json_err:
            logger.warning("JSON decoding failed for user %s: %s", self.user, json_err)
        return []

def fetch_repos(user: str) -> List[Dict[str, Any]]:
    """
    Retrieve public repositories for a validated GitHub user.
    """
    if not is_valid_username(user):
        raise ValueError("Invalid username")
    fetcher = GitHubFetcher(user)
    return fetcher.get_repos()

