import subprocess
import sys
import os
import unittest
from os import path as op

def _safe_run(argv, *, capture_output=True):
    if not isinstance(argv, list):
        raise TypeError("argv must be a list")
    shell_meta = {';', '|', '&', '$', '<', '>'}
    for a in argv:
        if not isinstance(a, str):
            raise TypeError("All argv elements must be strings")
        if any(c in a for c in shell_meta):
            raise ValueError("Argument contains forbidden shell metacharacter.")
    return subprocess.run(argv, capture_output=capture_output, shell=False)

class TestScriptSecurity(unittest.TestCase):
    def test_prevent_path_traversal_and_injection(self):
        malicious_path = op.join("..", "..", "malicious.txt")
        try:
            result = _safe_run(
                [sys.executable, SCRIPT, malicious_path],
            )
        except (OSError, ValueError, TypeError) as exc:
            self.fail(f"Execution failed: {exc}")
        self.assertNotEqual(
            result.returncode,
            0,
            "Script should not allow file creation outside its intended directory",
        )
        self.assertFalse(op.exists("malicious.txt"))
        self.assertFalse(op.exists(op.realpath(malicious_path)))

