class CocoDataset(data.Dataset):
    def __init__(self, root, anns, vocab, mode='train', transform=None):
        if mode not in {'train', 'val', 'test'}:
            raise ValueError("mode must be one of 'train', 'val', 'test'")

        self.root = os.path.abspath(root)
        if not os.path.isdir(self.root):
            raise FileNotFoundError(f"Image root directory not found: {self.root}")

        ann_path = os.path.abspath(anns)
        if not os.path.isfile(ann_path):
            raise FileNotFoundError(f"Annotation file not found: {ann_path}")

        try:
            with open(ann_path, 'r', encoding='utf-8') as f:
                self.anns = json.load(f)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse annotation JSON: {e}") from e
        except Exception as e:
            raise RuntimeError(f"Error loading annotations: {e}") from e

        if not isinstance(vocab, Vocabulary):
            raise TypeError("vocab must be an instance of Vocabulary")
        self.vocab = vocab

        if transform is not None and not callable(transform):
            raise TypeError("transform must be callable")
        self.transform = transform

        if mode == 'train':
            self.image_ids = [ann['id'] for ann in self.anns.get('images', [])]
        else:
            self.image_ids = [ann['id'] for ann in self.anns.get('images', [])]

        if not self.image_ids:
            raise RuntimeError("No images found in dataset")

    def __len__(self):
        return len(self.image_ids)

    def _secure_path(self, root, filename):
        if not isinstance(filename, str):
            raise ValueError("file_name must be a string")
        if os.path.isabs(filename):
            raise ValueError("file_name must be a relative path")
        # Normalize to collapse any '..' or '.' components
        norm_name = os.path.normpath(filename)
        if norm_name.startswith("..") or os.path.isabs(norm_name):
            raise ValueError(f"Invalid file_name: {filename}")
        # Construct absolute path
        full_path = os.path.abspath(os.path.join(root, norm_name))
        # Ensure the resulting path is still under the root directory
        if not os.path.commonpath([self.root, full_path]) == self.root:
            raise ValueError(f"File '{filename}' escapes root directory")
        return full_path

    def __getitem__(self, idx):
        try:
            img_id = self.image_ids[idx]
            img_meta = next(
                (img for img in self.anns.get('images', []) if img.get('id') == img_id), None
            )
            if img_meta is None:
                raise IndexError(f"Image ID {img_id} not found in annotations")
            file_name = img_meta.get('file_name')
            if file_name is None:
                raise KeyError(f"file_name missing for image ID {img_id}")
            img_path = self._secure_path(self.root, file_name)
            if not os.path.isfile(img_path):
                raise FileNotFoundError(f"Image file not found: {img_path}")
        except Exception as e:
            logging.error(f"Error retrieving image metadata: {e}")
            raise

        try:
            with Image.open(img_path) as img:
                img = img.convert('RGB')
                if self.transform:
                    img = self.transform(img)
                else:
                    img = np.array(img)
        except Exception as e:
            logging.error(f"Error opening image {img_path}: {e}")
            raise

        ann_list = self.anns.get('annotations', [])
        anns_for_image = [ann for ann in ann_list if ann.get('image_id') == img_id]
        try:
            if anns_for_image:
                caps = [ann['caption'] for ann in anns_for_image]
                tokenized = [self.vocab.numericalize(cap) for cap in caps]
                annotations = torch.tensor(tokenized, dtype=torch.long)
            else:
                annotations = torch.empty((0,), dtype=torch.long)
        except Exception as e:
            logging.error(f"Error processing annotations for image {img_id}: {e}")
            raise

        return img, annotations

