from typing import Any, Mapping, Optional

class WikibaseQuantity:
    @classmethod
    def from_dict(cls, data: Mapping[str, Any]):
        if not isinstance(data, Mapping):
            raise TypeError("Input must be a mapping")

        try:
            amount_val = data['amount']
        except KeyError as exc:
            raise ValueError("Missing required 'amount' field") from exc

        try:
            amount = Decimal(str(amount_val))
        except (ValueError, TypeError) as exc:
            raise ValueError("Invalid 'amount' value") from exc

        unit = data.get('unit')
        if unit is not None and not isinstance(unit, str):
            raise TypeError("Unit must be a string")

        def _parse_bound(key: str) -> Optional[Decimal]:
            val = data.get(key)
            if val is None:
                return None
            try:
                return Decimal(str(val))
            except (ValueError, TypeError) as exc:
                raise ValueError(f"Invalid '{key}'") from exc

        lower = _parse_bound('lowerBound')
        upper = _parse_bound('upperBound')

        if lower is not None and upper is not None and lower > upper:
            raise ValueError("lowerBound cannot be greater than upperBound")

        return cls(amount=amount, unit=unit, lower=lower, upper=upper)

