logger = logging.getLogger(__name__)

class ProblemUpdater:
    def __init__(self, db):
        self.db = db
        self.record = {}

    def update_solved_time(self, problem_id: int):
        """
        Update the solved_time field for a problem record.
        """
        cursor = self.db.cursor()
        try:
            solved_time = self.record.get("solved_at")
            if solved_time is None:
                raise ValueError("solved_at is missing from record")
            if not isinstance(solved_time, (datetime.datetime, datetime.date)):
                raise ValueError("Invalid solved time format")
            cursor.execute(
                "UPDATE problem SET solved_time = %s WHERE id = %s",
                (solved_time, problem_id),
            )
            self.db.commit()
        except Exception as exc:
            self.db.rollback()
            logger.error("Failed to update problem record: %s", exc)
            raise
        finally:
            cursor.close()

