def move_files(row_end, column_end, src_dir=Path("."), dst_dir=Path("temp")):
    if not isinstance(row_end, int) or not isinstance(column_end, int):
        logging.error("row_end and column_end must be integers")
        return
    if row_end <= 0 or column_end <= 0:
        logging.error("row_end and column_end must be positive")
        return

    dst_dir = dst_dir.resolve()
    try:
        dst_dir.mkdir(parents=True, exist_ok=True)
    except OSError as exc:
        logging.error(f"Could not create destination directory '{dst_dir}': {exc}")
        return

    filename_pattern = re.compile(r"^\d+-\d+\.jpg$")

    for r in range(row_end):
        for c in range(column_end):
            file_name = f"{1000 + c}-{1000 + row_end - r - 1}.jpg"

            if not filename_pattern.fullmatch(file_name):
                logging.warning(f"Invalid filename format: {file_name}")
                continue

            src_path = (src_dir / file_name).resolve()
            dst_path = dst_dir / src_path.name

            if not src_path.is_file():
                logging.warning(f"Source file does not exist: {src_path}")
                continue

            try:
                shutil.move(str(src_path), str(dst_path))
