import os
import configparser
import logging

logger = logging.getLogger(__name__)

# Resolve and ensure allowed directories are canonical
SAFE_DIRS = {
    os.path.realpath("/etc/knh"),
    os.path.realpath(os.path.expanduser("~/.knh"))
}


def getdict(d, n, defv):
    """
    Safely retrieve a dictionary value with a default.
    """
    return d.get(n, defv)


def read_settings(fn):
    """
    Read settings from a configuration file while enforcing security constraints.
    Returns a dictionary of configuration keys and values.
    """
    KNH_DATA = {}
    try:
        # Resolve symlinks and canonicalize path
        abs_path = os.path.abspath(fn)
        real_path = os.path.realpath(abs_path)

        # Ensure the file resides in one of the allowed directories
        if not any(os.path.commonpath([real_path, d]) == d for d in SAFE_DIRS):
            raise ValueError("Disallowed configuration path")

        # Verify the file exists
        if not os.path.isfile(real_path):
            raise FileNotFoundError

        # Read the configuration file
        with open(real_path, "r", encoding="utf-8") as f:
            parser = configparser.ConfigParser(interpolation=None)
            parser.read_file(f)

        # Extract configuration values
        for section in parser.sections():
            for key, val in parser.items(section):
                KNH_DATA[key] = val

    except ValueError:
        logger.error("Configuration path is not allowed")
    except FileNotFoundError:
        logger.error("Configuration file not found")
    except OSError:
        logger.error("Error accessing configuration file")
    except Exception:
        logger.exception("Unexpected error while reading configuration")
        KNH_DATA = {}

    return KNH_DATA

