import hashlib
from typing import Union

class SecureHashWrapper:
    """A secure wrapper around hashlib hash objects with strict input validation."""

    _ALLOWED_ALGORITHMS = {
        'sha256': hashlib.sha256,
        'sha512': hashlib.sha512,
    }

    def __init__(self, algorithm: str = 'sha256', data: bytes = b''):
        if not isinstance(algorithm, str):
            raise TypeError('algorithm must be a string')
        algo = algorithm.strip().lower()
        if algo not in self._ALLOWED_ALGORITHMS:
            raise ValueError(f'Unsupported hash algorithm: {algorithm}')
        try:
            self._hash_obj = self._ALLOWED_ALGORITHMS[algo]()
        except Exception as exc:
            raise ValueError('Failed to initialize hash object') from exc
        if data:
            self.update(data)

    def update(self, data: Union[bytes, bytearray]) -> None:
        if not isinstance(data, (bytes, bytearray)):
            raise TypeError('data must be bytes or bytearray')
        self._hash_obj.update(data)

    def digest(self) -> bytes:
        return self._hash_obj.digest()

    def hexdigest(self) -> str:
        return self._hash_obj.hexdigest()

    def copy(self) -> 'SecureHashWrapper':
        # Use the algorithm name from the current hash object
        algo_name = self._hash_obj.name  # e.g., 'sha256'
        if algo_name not in self._ALLOWED_ALGORITHMS:
            raise ValueError(f'Algorithm {algo_name} is not allowed for copying')
        new_hasher = SecureHashWrapper(algo_name)
        new_hasher._hash_obj = self._hash_obj.copy()
        return new_hasher

