import os
import platform
import signal
import subprocess
import sys

try:
    import psutil
except ImportError:
    psutil = None


def _process_belongs_to_current_user(pid: int) -> bool:
    if psutil is None:
        return True
    try:
        proc = psutil.Process(pid)
        proc_username = proc.username()
        if sys.platform == "win32":
            try:
                current_user = os.getlogin()
            except OSError:
                current_user = None
            if current_user is None:
                return False
            return proc_username.lower().endswith(current_user.lower())
        else:
            try:
                current_user = os.getlogin()
            except OSError:
                current_user = None
            return proc_username == current_user
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        return False


def kill_process_with_id(pid: int) -> None:
    if not isinstance(pid, int) or pid <= 0:
        raise ValueError("PID must be a positive integer")

    if pid in (0, 1, 2, 4) or (sys.platform != "win32" and pid < 100):
        raise PermissionError("Termination of system-critical process is prohibited")

    if not _process_belongs_to_current_user(pid):
        raise PermissionError("Process does not belong to the current user")

    try:
        if platform.system().lower() == "windows":
            windir = os.getenv("WINDIR", r"C:\Windows")
            taskkill_path = os.path.join(windir, "System32", "taskkill.exe")
            if not os.path.isfile(taskkill_path):
                raise RuntimeError("Required system utility not found: taskkill.exe")
            cmd = [taskkill_path, "/PID", str(pid), "/F"]
            subprocess.run(
                cmd,
                check=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=False,
            )
        else:
            os.kill(pid, signal.SIGTERM)
    except subprocess.CalledProcessError:
        raise RuntimeError(f"Failed to terminate process {pid}") from None
    except FileNotFoundError:
        raise RuntimeError("Required system utility not found") from None
    except PermissionError:
        raise PermissionError(f"Insufficient privileges to terminate process {pid}") from None
    except Exception:
        raise RuntimeError(f"Unexpected error when terminating process {pid}") from None

