import re
from pathlib import Path
from PIL import Image

ALLOWED_EXTENSIONS = {".jpg", ".jpeg", ".png", ".gif", ".bmp"}
RESIZE_REGEX = re.compile(r"^\d+x\d+$", re.ASCII)


def get_convert_path() -> Path:
    """Return a trusted absolute path to the ImageMagick convert binary."""
    env_path = os.getenv("IMAGICK_CONVERT_PATH")
    if env_path:
        path = Path(env_path).expanduser()
    else:
        path_str = shutil.which("convert")
        if not path_str:
            raise RuntimeError("ImageMagick 'convert' binary not found")
        path = Path(path_str)

    if not path.is_absolute():
        raise RuntimeError("ImageMagick convert path must be absolute")

    if not path.is_file() or not os.access(path, os.X_OK):
        raise RuntimeError("ImageMagick convert path is not executable")

    # Optional checksum verification
    expected_hash = os.getenv("IMAGICK_CONVERT_HASH")
    if expected_hash:
        with path.open("rb") as f:
            file_hash = hashlib.sha256(f.read()).hexdigest()
        if file_hash.lower() != expected_hash.lower():
            raise RuntimeError("ImageMagick convert binary checksum mismatch")

    # Ensure the binary is owned by root
    try:
        stat_info = path.stat()
    except Exception as exc:
        raise RuntimeError(f"Cannot stat convert binary: {exc}") from exc

    if stat_info.st_uid != 0:
        raise RuntimeError("ImageMagick convert binary is not owned by root")

    return path


def validate_image_file(image_path: Path) -> None:
    if not image_path.is_file():
        raise ValueError(f"Input file does not exist: {image_path}")
    if image_path.suffix.lower() not in ALLOWED_EXTENSIONS:
        raise ValueError(f"Unsupported file extension: {image_path.suffix}")
    try:
        with Image.open(image_path) as img:
            img.verify()
    except Exception as exc:
