import struct
import logging


class DatagramProcessor:
    MAX_PACKET_LENGTH = 4096

    def __init__(self, sock, logger=None):
        self.sock = sock
        self.root_logger = logger or logging.getLogger(__name__)

    def handle_datagram(self, packet, request):
        # Ensure packet is a bytes-like object
        if not isinstance(packet, (bytes, bytearray)):
            self.root_logger.warning(
                "Invalid packet type: %s", type(packet).__name__
            )
            return

        packet_len = len(packet)
        if packet_len > self.MAX_PACKET_LENGTH:
            self.root_logger.warning(
                "Datagram too large: %d bytes", packet_len
            )
            return

        # Safely unpack the command byte
        try:
            (cmd,) = struct.unpack(">B", packet[:1])
        except struct.error:
            self.root_logger.warning("Malformed packet: unable to unpack command")
            return

        # Destination address must be a (host, port) tuple
        send_address = getattr(request, "addr", None)
        if not isinstance(send_address, tuple) or len(send_address) != 2:
            self.root_logger.warning(
                "Invalid or missing destination address for command 0x%02x", cmd
            )
            return

        # Handle supported commands
        response = None
        if cmd == 0x01:  # Echo
            response = packet[1:]
        elif cmd == 0x02:  # Ping
            response = b"PONG"
        else:
            self.root_logger.warning("Unhandled command 0x%02x", cmd)
            return

        if response is None:
            self.root_logger.warning(
                "No response prepared for command 0x%02x", cmd
            )
            return

        # Send the response safely
        try:
            self.sock.sendto(response, send_address)
        except Exception:
            self.root_logger.exception("Error sending datagram response")

import pathlib
import json

BASE_DIR = pathlib.Path(__file__).resolve().parent

class SecurePlaybackHandler:
    def __init__(self):
        self.recording_shelf = None
        self.playback_shelf = None

    def playbackFile(self, filename, cache=False):
        if self.recording_shelf is not None:
            raise RuntimeError("Recording shelf already initialized")

        if not isinstance(filename, (str, pathlib.PurePath)):
            raise ValueError("Invalid filename type; expected string or pathlib.Path")

        path_obj = pathlib.Path(filename)

        # Reject paths containing user expansion shortcuts or absolute Windows paths
        if "~" in path_obj.parts or (path_obj.is_absolute() and path_obj.drive):
            raise ValueError("Invalid filename: absolute paths or user shortcuts are not allowed")

        # Reject directory traversal components
        if any(part == ".." for part in path_obj.parts):
            raise ValueError("Invalid filename: directory traversal detected")

        # Resolve to an absolute path
        resolved = (BASE_DIR / path_obj).resolve()

        # Ensure the resolved path is within the base directory
        if not resolved.is_relative_to(BASE_DIR):
            raise ValueError("Invalid filename: path escapes base directory")

        if not resolved.is_file():
            raise FileNotFoundError(f"Playback file not found: {resolved}")

        try:
            with open(resolved, "r", encoding="utf-8") as f:
                data = json.load(f)
        except json.JSONDecodeError as exc:
            raise RuntimeError("Playback file contains invalid JSON") from exc
        except OSError as exc:
            raise RuntimeError("Failed to open playback file securely") from exc

        self.playback_shelf = data
        # cache parameter retained for interface compatibility but not used in this implementation
        return self.playback_shelf

