def _make_deprecated_setter(new_name: str, name: str, version: str):
    """
    Create a setter that forwards deprecated attribute writes to the new attribute.
    """
    if not isinstance(new_name, str) or not isinstance(name, str) or not isinstance(version, str):
        raise TypeError("new_name, name, and version must be strings")
    def setter(self, value):
        # Log the deprecation warning without exposing the value
        self.log.warning(
            "KubeSpawner.%s is deprecated in %s. Use KubeSpawner.%s",
            name,
            version,
            new_name,
        )
        if not hasattr(type(self), new_name):
            raise AttributeError(f"Unknown attribute {new_name}")
        setattr(self, new_name, value)
    return setter

