import argparse
import json
import os
import uuid
from pathlib import Path
from typing import Dict

import numpy as np


def write_json_atomic(filepath: Path, data: Dict) -> None:
    tmp = Path(filepath.parent, f".tmp-{uuid.uuid4().hex}")
    tmp.write_text(json.dumps(data, separators=(",", ":")), encoding="utf-8")
    tmp.chmod(0o600)
    tmp.replace(filepath)


def is_within(base: Path, target: Path) -> bool:
    try:
        target.relative_to(base)
        return True
    except ValueError:
        return False


def main() -> None:
    parser = argparse.ArgumentParser(description="Compute mean of a binary float64 file.")
    parser.add_argument("filename", help="Path to the binary data file")
    args = parser.parse_args()

    script_dir = Path(__file__).resolve().parent
    results_dir = script_dir / "results"
    if not results_dir.is_dir():
        raise RuntimeError(f"Missing results directory: {results_dir}")

    orig_path = Path(args.filename)
    if not orig_path.is_absolute():
        orig_path = orig_path.resolve()

    if not orig_path.is_file():
        raise FileNotFoundError(f"Required data file not found: {orig_path}")

    if not is_within(results_dir, orig_path):
        raise RuntimeError("Path traversal detected or file outside results directory")

    if orig_path.is_symlink():
        real_path = orig_path.resolve()
        if not is_within(results_dir, real_path):
            raise RuntimeError("Symlink points outside results directory")

    try:
        raw_bytes = orig_path.read_bytes()
    except Exception as exc:
        raise RuntimeError("Unable to read the data file") from exc

    try:
        data_array = np.frombuffer(raw_bytes, dtype=np.float64)
    except Exception as exc:
        raise RuntimeError("Failed to parse data into array") from exc

    try:
        mean_value = float(np.mean(data_array))
    except Exception:
        mean_value = None

    result_file = results_dir / "analysis_results.json"
    try:
        write_json_atomic(result_file, {"mean_value": mean_value})
    except Exception as exc:
        raise RuntimeError("Unable to write analysis result to disk") from exc

    print(f"Analysis complete. Mean value stored in {result_file}.")


if __name__ == "__main__":
    main()

