import os
import logging
import hashlib
from urllib.parse import unquote, urlparse

from django.conf import settings

logger = logging.getLogger(__name__)


def _validate_settings() -> None:
    if not hasattr(settings, "STATIC_URL") or not isinstance(settings.STATIC_URL, str):
        raise RuntimeError("STATIC_URL must be defined in settings and must be a string")
    if not hasattr(settings, "STATIC_ROOT") or not isinstance(settings.STATIC_ROOT, str):
        raise RuntimeError("STATIC_ROOT must be defined in settings and must be a string")


def get_local_static_path(url: str) -> str:
    """Convert a static URL to its corresponding local file system path."""
    if not isinstance(url, str):
        raise TypeError("URL must be a string")

    _validate_settings()

    static_url = settings.STATIC_URL
    static_root = settings.STATIC_ROOT

    if not static_url.endswith("/"):
        static_url = static_url.rstrip("/") + "/"

    parsed = urlparse(url)
    if parsed.scheme or parsed.netloc:
        raise ValueError("URL must be a relative path within STATIC_URL")

    if not parsed.path.startswith(static_url):
        raise ValueError("URL does not start with STATIC_URL")

    relative_path = unquote(parsed.path[len(static_url) :])

    if ".." in relative_path.split(os.sep):
        raise ValueError("URL contains prohibited path traversal sequences")

    relative_path = os.path.normpath(relative_path).lstrip(os.sep)

    local_path = os.path.join(static_root, relative_path)

    abs_static_root = os.path.abspath(static_root)
    abs_local_path = os.path.abspath(local_path)

    if os.path.commonpath([abs_static_root, abs_local_path]) != abs_static_root:
        raise ValueError("Resolved path is outside of STATIC_ROOT")

    return local_path


def _compute_file_hash(filepath: str, buffer_size: int = 65536) -> str:
    if not isinstance(filepath, str):
        raise TypeError("File path must be a string")
    if not os.path.exists(filepath):
        raise FileNotFoundError(f"File not found: {filepath}")
    if not os.access(filepath, os.R_OK):
        raise PermissionError(f"Cannot read file: {filepath}")

    sha256 = hashlib.sha256()
    try:
        with open(filepath, "rb") as fh:
            for chunk in iter(lambda: fh.read(buffer_size), b""):
                sha256.update(chunk)
    except (OSError, PermissionError) as exc:
        logger.error("Error reading file %s: %s", filepath, exc)
        raise
    return sha256.hexdigest()

