import os
import re
from pathlib import Path

class FileProcessor:
    def __init__(self, path, dest_stream):
        self.path = path
        self.args = {"dest": dest_stream}

    def main(self):
        # Resolve the source path and verify it is a regular file
        src_path = Path(self.path).resolve(strict=True)
        if not src_path.is_file():
            raise ValueError("The source path is not a valid file.")

        # Resolve the destination path using the stream's name
        dest_stream = self.args["dest"]
        if not hasattr(dest_stream, "name"):
            raise ValueError("Destination stream must have a 'name' attribute.")
        dest_path = Path(dest_stream.name).resolve()

        # Ensure the destination directory exists and is writable
        dest_dir = dest_path.parent
        if not dest_dir.is_dir():
            raise ValueError("Destination directory does not exist.")
        if not os.access(dest_dir, os.W_OK):
            raise PermissionError("Destination directory is not writable.")

        # Restrict the destination file name to safe ASCII characters
        if not re.fullmatch(r"[A-Za-z0-9_.-]+", dest_path.name):
            raise ValueError("Destination file name contains disallowed characters.")

        chunk_size = 64 * 1024  # 64 KiB
        bytes_written = 0

        try:
            with src_path.open("rb") as src_file:
                while True:
                    chunk = src_file.read(chunk_size)
                    if not chunk:
                        break
                    dest_stream.write(chunk)
                    bytes_written += len(chunk)
            dest_stream.flush()
        except (OSError, IOError) as exc:
            raise RuntimeError("An error occurred during file processing.") from exc
        finally:
            dest_stream.close()

        return bytes_written

