class MemorySysLogHandler(logging.Handler):
    """
    A handler that writes syslog-style messages to a BytesIO buffer.
    """

    def __init__(self, output_stream: io.BytesIO, event: threading.Event | None = None):
        super().__init__()
        if not isinstance(output_stream, io.BytesIO):
            raise TypeError("output_stream must be a BytesIO instance")
        self.output_stream = output_stream
        self.ident = ""
        self.event = event
        self.lock = threading.Lock()

    @staticmethod
    def _get_priority(levelno: int) -> int:
        if levelno >= logging.CRITICAL:
            syslog_level = 2
        elif levelno >= logging.ERROR:
            syslog_level = 3
        elif levelno >= logging.WARNING:
            syslog_level = 4
        elif levelno >= logging.INFO:
            syslog_level = 6
        else:
            syslog_level = 7
        facility = 1
        return (facility << 3) | syslog_level

    @staticmethod
    def _sanitize(text: str) -> str:
        sanitized = _SANITIZE_PATTERN.sub("", text)
        return sanitized.replace("
", " ").replace("", "")

    def emit(self, record: logging.LogRecord) -> None:
        try:
            safe_ident = self._sanitize(str(self.ident) if self.ident is not None else "")
