BASE_OUTPUT_DIR = Path(__file__).resolve().parent


def _validate_binary(encryptor_path: Path) -> None:
    if not encryptor_path.is_file():
        raise FileNotFoundError(f"Encryptor binary not found: {encryptor_path}")
    mode = encryptor_path.stat().st_mode
    if not (mode & (stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH)):
        raise PermissionError(f"Encryptor binary is not executable: {encryptor_path}")

    sha256_hash = hashlib.sha256()
    with encryptor_path.open("rb") as f:
        for block in iter(lambda: f.read(65536), b""):
            sha256_hash.update(block)
    if sha256_hash.hexdigest() != EXPECTED_ENCRYPTOR_HASH:
        raise ValueError(
            f"Encryptor binary hash mismatch: expected {EXPECTED_ENCRYPTOR_HASH}, "
            f"got {sha256_hash.hexdigest()}"
        )


def _validate_hex_key(key: str, name: str) -> None:
    if not re.fullmatch(r"[A-Fa-f0-9]{64}", key):
        raise ValueError(f"Invalid {name} format (must be 64âhexâcharacters)")


def _validate_pack_name(name: str) -> None:
    if not re.fullmatch(r"[A-Za-z0-9_\-]+", name):
        raise ValueError("Invalid pack_name")


def _resolve_output(name: str, allowed_base: Path) -> Path:
    out = Path(name).expanduser().resolve()
    if not out.is_relative_to(allowed_base):
        raise ValueError(f"Output path outside allowed directory: {out}")
    return out


def _prepare_output_path(out_path: Path) -> None:
    parent = out_path.parent
    try:
        parent.mkdir(parents=True, exist_ok=True, mode=0o700)
    except Exception as e:
        raise RuntimeError(f"Could not create directory {parent!s}: {e}")
    # Ensure the path is a directory and not a symlink
    if not parent.is_dir():
        raise RuntimeError(f"Parent path is not a directory: {parent!s}")
    if parent.is_symlink():
        raise RuntimeError(f"Parent directory is a symlink: {parent!s}")
    if not os.access(parent, os.W_OK):
        raise PermissionError(f"Directory not writable: {parent!s}")


def encrypt_and_cleanup(
    pack_name: str,
    encryption_key: str,
    secondary_encryption_key: str,
    zip_pack_path: str,
    output_file: str,
    secondary_encryption_key_output_file: str,
) -> None:
    encryptor_path = BASE_OUTPUT_DIR / "encryptor"
    _validate_binary(encryptor_path)

    _validate_pack_name(pack_name)
    _validate_hex_key(encryption_key, "encryption_key")
    _validate_hex_key(secondary_encryption_key, "secondary_encryption_key")

    source_zip = Path(zip_pack_path)
    if not source_zip.is_file():
        raise FileNotFoundError(f"Source zip not found: {source_zip}")

    primary_output = _resolve_output(output_file, BASE_OUTPUT_DIR)
    secondary_output = _resolve_output(secondary_encryption_key_output_file, BASE_OUTPUT_DIR)

    _prepare_output_path(primary_output)
    _prepare_output_path(secondary_output)

    def _run_encryption(src: Path, out: Path, key: str) -> None:
        cmd = [str(encryptor_path), str(src), str(out)]
        try:
            result = subprocess.run(
                cmd,
                input=key.encode(),
                capture_output=True,
                text=True,
                check=False,
            )
        except Exception as exc:
            raise RuntimeError(f"Failed to execute encryptor for {src!s} -> {out!s}") from exc
        if result.returncode != 0:
            logger.error(f"Encryption binary error for {src!s} -> {out!s}: {result.stderr!r}")
            raise RuntimeError(f"Encryption failed for {src!s} -> {out!s}")

    try:
        _run_encryption(source_zip, primary_output, encryption_key)
    except Exception as e:
        raise RuntimeError("Primary encryption failed") from e

    try:
        _run_encryption(source_zip, secondary_output, secondary_encryption_key)
    except Exception as e:
        raise RuntimeError("Secondary encryption failed") from e

    try:
        source_zip.unlink()
    except Exception as e:
        logger.warning(f"Could not delete unencrypted zip: {e}")

