    @classmethod
    def _is_valid_username(cls, username: str) -> bool:
        if not (3 <= len(username) <= 30):
            return False
        if not re.match(r"^[A-Za-z][A-Za-z0-9_]*$", username):
            return False
        reserved = {"admin", "root", "superuser", "__admin"}
        if username.lower() in reserved:
            return False
        return True

    @classmethod
    def setUpClass(cls):
        super().setUpClass()
        logger = logging.getLogger(__name__)
        User = get_user_model()

        try:
            validate_email(cls.email)
        except ValidationError as exc:
            logger.error("Provided test email is invalid: %s", exc)
            raise

        if not cls._is_valid_username(cls.username):
            logger.error("Provided test username does not meet constraints: %s", cls.username)
            raise ValueError("Username does not meet application constraints")

        try:
            with transaction.atomic():
                if not User.objects.filter(username=cls.username).exists():
                    cls._test_password = secrets.token_urlsafe(16)
                    cls.test_user = User.objects.create_user(
                        username=cls.username,
                        email=cls.email,
                        password=cls._test_password,
                        is_staff=cls.is_staff,
                        is_superuser=cls.is_superuser,
                    )
                else:
                    cls.test_user = User.objects.get(username=cls.username)

                view_perm = Permission.objects.filter(codename="view_user").first()
                if view_perm:
                    cls.test_user.user_permissions.add(view_perm)
                cls.test_user.save()
        except OperationalError as exc:
            logger.error("Database error during user creation: %s", exc)
            raise

    def setUp(self):
        super().setUp()
        if self.is_anonymous:
            self.client.logout()
        else:
            try:
                self.client.force_login(self.test_user)
            except Exception as exc:
                self.fail(f"Login failed: {exc}")

    def tearDown(self):
        logger = logging.getLogger(__name__)
        allowed_perms = {"view_user"}
        try:
            for perm in list(self.test_user.user_permissions.all()):
                if perm.codename in allowed_perms:
                    try:
                        self.test_user.user_permissions.remove(perm)
                    except Exception as exc:
                        logger.warning("Failed to remove permission %s: %s", perm.codename, exc)
        except Exception as exc:
            logger.error("Error during permission cleanup: %s", exc)
