import os
import re
import sqlite3

# Accepted SQLite column types
ALLOWED_COLUMN_TYPES = {
    "INTEGER", "TEXT", "REAL", "BLOB", "NUMERIC",
    "BOOLEAN", "DATE", "DATETIME"
}

# Base directory allowed for database files (environment variable or current)
ALLOWED_DB_DIR = os.path.abspath(os.getenv("DB_DIR", "."))

def _normalize_db_path(dbname: str) -> str:
    db_path = os.path.abspath(dbname)
    if not db_path.startswith(ALLOWED_DB_DIR):
        raise ValueError("Database path not in allowed directory")
    if not db_path.endswith(".db"):
        raise ValueError("Database file must have .db extension")
    return db_path

def _validate_table_name(name: str) -> str:
    if not isinstance(name, str):
        raise TypeError("Table name must be a string")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", name):
        raise ValueError("Invalid table name")
    return name

def _validate_table_definition(definition: str) -> str:
    if not isinstance(definition, str):
        raise TypeError("Table definition must be a string")
    parts = [p.strip() for p in definition.split(",") if p.strip()]
    if not parts:
        raise ValueError("Empty table definition")
    validated = []
    for part in parts:
        tokens = part.split()
        if len(tokens) < 2:
            raise ValueError(f"Invalid column definition: {part}")
        col_name, col_type = tokens[0], tokens[1]
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", col_name):
            raise ValueError(f"Invalid column name: {col_name}")
        if col_type.upper() not in ALLOWED_COLUMN_TYPES:
            raise ValueError(f"Unsupported column type: {col_type}")
        validated.append(f"{col_name} {col_type.upper()}")
    return ", ".join(validated)

def CreateTable(dbname: str, table: str, table_define: str) -> None:
    dbname = _normalize_db_path(dbname)
    table = _validate_table_name(table)
    clean_define = _validate_table_definition(table_define)
    sql = f"CREATE TABLE IF NOT EXISTS `{table}` ({clean_define})"
    conn = None
    cur = None
    try:
        conn = sqlite3.connect(dbname, timeout=30, isolation_level="DEFERRED")
        cur = conn.cursor()
        cur.execute(sql)
        conn.commit()
    except sqlite3.Error:
        raise RuntimeError("Error creating table")
    finally:
        if cur:
            cur.close()
        if conn:
            conn.close()

