import os
import re
import stat

def _sanitize_path(path: str) -> str:
    """Return a safe absolute path and verify it exists, is under /dev, and is a block device."""
    safe_path = os.path.realpath(path)
    if not safe_path.startswith("/dev/"):
        raise ValueError("Device path must be under /dev.")
    if not os.path.exists(safe_path):
        raise ValueError("Specified device path does not exist.")
    if not stat.S_ISBLK(os.stat(safe_path).st_mode):
        raise ValueError("Specified path is not a block device.")
    return safe_path

def _sanitize_int(value: object, name: str, max_allowed: int) -> str:
    """Ensure that a numeric value is a positive integer within the allowed range."""
    try:
        val = int(value)
    except (ValueError, TypeError):
        raise ValueError(f"Invalid {name}.")
    if val <= 0 or val > max_allowed:
        raise ValueError(f"{name} must be between 1 and {max_allowed}.")
    return str(val)

def build_target_config(device_path: str, auth: dict | None = None) -> dict:
    """
    Construct a target configuration dictionary with validated and sanitized data.
    """
    ret: dict = {
        "data": {
            "device_path": None,
            "qos_specs": {
                "total_bytes_sec": "102400",
                "read_iops_sec": "200",
            },
        }
    }

    # Sanitize and assign device path
    ret["data"]["device_path"] = _sanitize_path(device_path)

    # Sanitize QoS values
    qos = ret["data"]["qos_specs"]
    qos["total_bytes_sec"] = _sanitize_int(
        qos["total_bytes_sec"], "total_bytes_sec", 10**9
    )
    qos["read_iops_sec"] = _sanitize_int(
        qos["read_iops_sec"], "read_iops_sec", 10**6
    )

    # Optional authentication handling
    if auth:
        if not isinstance(auth, dict):
            raise ValueError("Authentication information must be a dictionary.")
        method = auth.get("method", "CHAP")
        username = auth.get("username")
        if not isinstance(username, str) or not username:
