from typing import Dict, Union

def parse_stat_file(stat_file: Union[str, pathlib.Path], *, base_dir: Union[str, pathlib.Path] = None) -> Dict[str, float]:
    # Resolve base directory
    if base_dir is None:
        base_dir = pathlib.Path(__file__).parent.resolve()
    else:
        base_dir = pathlib.Path(base_dir).resolve()
    if not base_dir.is_dir():
        raise ValueError(f"Base directory '{base_dir}' does not exist or is not a directory")

    # Validate stat_file path
    if not isinstance(stat_file, (str, pathlib.Path)):
        raise ValueError("stat_file must be a string or Path")
    stat_path = pathlib.Path(stat_file)

    # Canonicalize and ensure the file is within the base directory
    resolved_path = (base_dir / stat_path).resolve()
    try:
        resolved_path.relative_to(base_dir)
    except ValueError:
        raise ValueError("stat_file path escapes the trusted base directory")

    if not resolved_path.is_file():
        raise ValueError(f"Stat file '{resolved_path}' does not exist or is not a regular file")

    # Parse the stat file line by line, limiting to MAX_LINES
    MAX_LINES = 10000
    stats: Dict[str, float] = {}
    with resolved_path.open('r', encoding='utf-8') as file:
        for line_number, raw_line in zip(range(1, MAX_LINES + 1), file):
            line = raw_line.strip()
            if not line or line.startswith('#'):
                continue
            if '=' not in line:
                continue
            key, value = map(str.strip, line.split('=', 1))
            if not key.isidentifier():
                continue
            try:
                num_value = float(value)
            except ValueError:
                continue
            stats[key] = num_value

    if not stats:
        raise ValueError(f"No valid statistics found in '{resolved_path}'")
    return stats

