class SecureCoinbaseClient:
    BASE_URL = "https://api.coinbase.com/v2"

    def __init__(self, api_key: str, api_secret: str, passphrase: str):
        if not isinstance(api_key, str) or not api_key:
            raise ValueError("Invalid API key")
        if not isinstance(api_secret, str) or not api_secret:
            raise ValueError("Invalid API secret")
        if not isinstance(passphrase, str) or not passphrase:
            raise ValueError("Invalid passphrase")
        self._api_key = api_key
        self._api_secret = api_secret
        self._passphrase = passphrase

    def _build_signature(self, method: str, endpoint: str, body: str, timestamp: str) -> str:
        prehash = f"{timestamp}{method}{endpoint}{body}"
        signature = hmac.new(
            self._api_secret.encode("utf-8"),
            prehash.encode("utf-8"),
            hashlib.sha256,
        ).digest()
        return base64.b64encode(signature).decode("utf-8")

    def _request(self, method: str, endpoint: str, payload: dict | None = None) -> dict:
        if not isinstance(endpoint, str) or not endpoint.startswith("/"):
            raise ValueError("Endpoint must be a string that starts with '/'")
        url = f"{self.BASE_URL}{endpoint}"
        parsed_url = urllib.parse.urlparse(url)
        base_parsed = urllib.parse.urlparse(self.BASE_URL)
        if parsed_url.scheme != "https" or parsed_url.netloc.lower() != base_parsed.netloc.lower():
            raise ValueError(f"Invalid URL scheme or host: {url}")

        body_str = json.dumps(payload, separators=(",", ":")) if payload else ""
        timestamp = str(int(time.time()))
        signature = self._build_signature(method, endpoint, body_str, timestamp)

        headers = {
            "CB-ACCESS-KEY": self._api_key,
            "CB-ACCESS-SIGN": signature,
            "CB-ACCESS-TIMESTAMP": timestamp,
            "CB-ACCESS-PASSPHRASE": self._passphrase,
            "Content-Type": "application/json",
        }

        data = body_str.encode("utf-8") if payload else None
        req = urllib.request.Request(url, data=data, headers=headers, method=method)

        # Additional runtime validation of the request URL
        req_parsed = urllib.parse.urlparse(req.full_url)
        if req_parsed.scheme != "https" or req_parsed.netloc.lower() != base_parsed.netloc.lower():
            raise ValueError(f"Request URL is not allowed: {req.full_url}")

        try:
            with urllib.request.urlopen(req, timeout=10, context=ssl_context) as resp:
                resp_body = resp.read()
                try:
                    return json.loads(resp_body.decode("utf-8"))
                except json.JSONDecodeError:
                    log.warning("Received non-JSON response from Coinbase")
                    return {}
        except urllib.error.HTTPError as exc:
            log.error(f"HTTPError {exc.code} for {endpoint}")
            raise
        except urllib.error.URLError as exc:
            log.error(f"URLError for {endpoint}: {exc.reason}")
            raise
        except Exception as exc:
            log.error(f"Unexpected error during request to {endpoint}: {exc}")
            raise

    def create_order(
        self,
        product_id: str,
