import ast
import logging

_LOGGER = logging.getLogger(__name__)

class SafeEvaluator:
    @staticmethod
    def _eval(node, globals_dict, locals_dict):
        if isinstance(node, ast.Expression):
            return SafeEvaluator._eval(node.body, globals_dict, locals_dict)

        if isinstance(node, ast.BoolOp):
            vals = [SafeEvaluator._eval(v, globals_dict, locals_dict) for v in node.values]
            if isinstance(node.op, ast.And):
                return all(vals)
            if isinstance(node.op, ast.Or):
                return any(vals)
            raise ValueError(f"Unsupported BoolOp: {ast.dump(node)}")

        if isinstance(node, ast.UnaryOp):
            operand = SafeEvaluator._eval(node.operand, globals_dict, locals_dict)
            if isinstance(node.op, ast.Not):
                return not operand
            raise ValueError(f"Unsupported UnaryOp: {ast.dump(node)}")

        if isinstance(node, ast.Compare):
            left = SafeEvaluator._eval(node.left, globals_dict, locals_dict)
            for op, comparator in zip(node.ops, node.comparators):
                right = SafeEvaluator._eval(comparator, globals_dict, locals_dict)
                if isinstance(op, ast.Eq):
                    if left != right:
                        return False
                elif isinstance(op, ast.NotEq):
                    if left == right:
                        return False
                elif isinstance(op, ast.Lt):
                    if not left < right:
                        return False
                elif isinstance(op, ast.LtE):
                    if not left <= right:
                        return False
                elif isinstance(op, ast.Gt):
                    if not left > right:
                        return False
                elif isinstance(op, ast.GtE):
                    if not left >= right:
                        return False
                else:
                    raise ValueError(f"Unsupported comparison operator: {ast.dump(op)}")
                left = right
            return True

        if isinstance(node, ast.Call):
            if not isinstance(node.func, ast.Name):
                raise ValueError("Only simple function calls allowed")
            func_name = node.func.id
            if func_name not in globals_dict:
                raise ValueError(f"Function {func_name} not allowed")
            func = globals_dict[func_name]
            args = [SafeEvaluator._eval(arg, globals_dict, locals_dict) for arg in node.args]
            kwargs = {kw.arg: SafeEvaluator._eval(kw.value, globals_dict, locals_dict) for kw in node.keywords}
            return func(*args, **kwargs)

        if isinstance(node, ast.Name):
            if node.id in globals_dict:
                return globals_dict[node.id]
            if node.id in locals_dict:
                return locals_dict[node.id]
            raise ValueError(f"Unknown identifier: {node.id}")

        if isinstance(node, ast.Constant):
            return node.value

        raise ValueError(f"Unsupported AST node: {ast.dump(node)}")

    @staticmethod
    def evaluate(expr, globals_dict, locals_dict=None):
        if locals_dict is None:
            locals_dict = {}
        tree = ast.parse(expr, mode='eval')
        return SafeEvaluator._eval(tree, globals_dict, locals_dict)


