import re
import shlex
import subprocess
from typing import List, Dict, Any


class InvalidCommandError(ValueError):
    """Raised when a command is not allowed or is malformed."""


class CommandExecutionError(RuntimeError):
    """Raised when the command execution fails."""


# Policy: allowed commands and flags for rpm, dnf, and yum.
POLICY: Dict[str, Dict[str, set]] = {
    "rpm": {
        "commands": {"list", "info", "check"},
        "flags": {"-q", "--quiet", "-v", "--verbose", "-qa"},
    },
    "dnf": {
        "commands": {"list", "info", "check"},
        "flags": {"-q", "--quiet", "-v", "--verbose"},
    },
    "yum": {
        "commands": {"list", "info", "check"},
        "flags": {"-q", "--quiet", "-v", "--verbose"},
    },
}


def _validate_token(token: str, tool_cfg: Dict[str, set]) -> None:
    """Validate a single token of the command."""
    # Reject characters that could alter command execution.
    if any(ch in token for ch in [">", "<", "|", ";", "&", "$", "`", "$(", ")"]):
        raise InvalidCommandError(f"Token '{token}' contains disallowed characters")

    if token.startswith(("--", "-")):
        if token not in tool_cfg["flags"]:
            raise InvalidCommandError(f"Disallowed flag '{token}'")
        return

    if token in tool_cfg["commands"]:
        return

    # Allow only safe alphanumeric and certain punctuation.
    if not re.fullmatch(r"[A-Za-z0-9._-]+", token):
        raise InvalidCommandError(f"Invalid argument '{token}'")


def _validate_command_parts(parts: List[str]) -> None:
    """Validate the list of command parts."""
    if not parts:
        raise InvalidCommandError("Empty command")

    tool = parts[0]
    if tool not in POLICY:
        raise InvalidCommandError(f"Tool '{tool}' is not allowed")

    tool_cfg = POLICY[tool]
    for token in parts[1:]:
        _validate_token(token, tool_cfg)


def execute_package_command(command: str, expected_output: str, context: Any) -> None:
    """Validate, execute a package manager command, and compare its output against the expected result."""
    cmd_str = command.strip()
    try:
        cmd_parts = shlex.split(cmd_str)
    except Exception as exc:
        raise InvalidCommandError(f"Failed to parse command: {exc}") from exc

    _validate_command_parts(cmd_parts)

    tool = cmd_parts[0]
    # Construct safe command list with explicit executable
    safe_cmd = [tool] + cmd_parts[1:]

    try:
        exec_res = subprocess.run(
            safe_cmd,
            capture_output=True,
            encoding="utf-8",
            check=True,
            timeout=30,
            executable=tool,
            env={"LANG": "C"},
        )
    except subprocess.TimeoutExpired as exc:
        raise CommandExecutionError("Command execution timed out") from exc
    except subprocess.CalledProcessError as exc:
        stdout = exc.stdout.strip() if exc.stdout else ""
        stderr = exc.stderr.strip() if exc.stderr else ""
        raise CommandExecutionError(
            f"Command execution failed: {stderr or stdout}"
        ) from exc

    actual_output = exec_res.stdout.strip()
    expected_output_clean = expected_output.strip()

    if actual_output != expected_output_clean:
        raise AssertionError(
            f"Expected output '{expected_output_clean}', but got '{actual_output}'"
        )

    context.command_output = actual_output
    context.command_exit_status = exec_res.returncode
    context.post_rpm_packages = get_rpm_package_list()
    context.post_rpm_packages_version = get_rpm_package_version_list()
    context.post_dnf_packages_version = get_dnf_package_version_list()

