import io
import json
import logging
import pickle
from pickle import Unpickler, UnpicklingError

logger = logging.getLogger(__name__)

class RestrictedUnpickler(Unpickler):
    """
    Unpickler that only allows unpacking of a limited set of builtin types.
    Any other class will raise UnpicklingError.
    """
    _allowed = {"builtins": {"dict", "list", "tuple", "str", "int", "float", "bool", "NoneType"}}

    def find_class(self, module, name):
        if module in self._allowed and name in self._allowed[module]:
            return super().find_class(module, name)
        raise UnpicklingError(f"Disallowed pickled object {module}.{name}")

def _validate_loaded_object(obj, max_depth: int = 1000):
    """
    Validate that the deserialized object is composed only of safe primitive types.
    Recursion depth is bounded to avoid stack overflows.
    """
    allowed_primitive = (str, int, float, bool, type(None))
    stack = [(obj, 0)]
    while stack:
        current, depth = stack.pop()
        if depth > max_depth:
            raise ValueError("Object depth exceeds maximum allowed limit")
        if isinstance(current, allowed_primitive):
            continue
        if isinstance(current, dict):
            for key, value in current.items():
                if not isinstance(key, allowed_primitive):
                    raise ValueError(f"Invalid key type: {type(key).__name__}")
                stack.append((value, depth + 1))
            continue
        if isinstance(current, (list, tuple)):
            for item in current:
                stack.append((item, depth + 1))
            continue
        raise ValueError(f"Unsupported type encountered: {type(current).__name__}")

class TestPickleSecurity:
    def test_pickle_2(self):
        complex_obj = {"a": [1, 2, 3], "b": {"nested": True}}
        serialized = pickle.dumps(complex_obj, protocol=pickle.HIGHEST_PROTOCOL)
        deserialized = self._safe_unpickle(serialized)
        if complex_obj != deserialized:
            raise AssertionError("Deserialized object does not match original")

    def _safe_unpickle(self, data: bytes):
        if not isinstance(data, (bytes, bytearray)):
            raise TypeError("Unpickling data must be bytes")
        if len(data) > 10**6:  # 1 MB limit
            raise ValueError("Unpickling data too large")
        try:
            result = RestrictedUnpickler(io.BytesIO(data)).load()
        except UnpicklingError as e:
            logger.debug("UnpicklingError: %s", e)
            raise ValueError("Unpickling failed") from e
        except Exception as e:
            logger.debug("Exception during unpickling: %s", e)
            raise ValueError("Unpickling failed") from e
        _validate_loaded_object(result)
        return result

    def test_safe_unpickle_with_valid_data(self):
        obj = {"key": "value", "numbers": [1, 2, 3]}
        pickled = pickle.dumps(obj, protocol=pickle.HIGHEST_PROTOCOL)
        result = self._safe_unpickle(pickled)
        if obj != result:
            raise AssertionError("Unpickled data does not match original")

    def test_safe_unpickle_with_invalid_data(self):
        bad_data = b"not a pickle"
        try:
            self._safe_unpickle(bad_data)
        except ValueError:
            pass
        else:
            raise AssertionError("Expected ValueError for bad data")

    def test_pickle_protocol_selection(self):
        data = {"msg": "test", "id": 123}
        for protocol in (pickle.DEFAULT_PROTOCOL, pickle.HIGHEST_PROTOCOL):
            pickled = pickle.dumps(data, protocol=protocol)
            unpickled = self._safe_unpickle(pickled)
            if unpickled != data:
                raise AssertionError("Unpickled data does not match original")

