import ast
import logging
import operator
from types import MappingProxyType
from typing import Any, Callable, Mapping, Dict, Optional

def safe_eval(expr: str, allowed_builtins: Mapping[str, Callable]) -> Any:
    if not isinstance(expr, str):
        raise TypeError("expr must be a string")
    if not isinstance(allowed_builtins, Mapping):
        raise TypeError("allowed_builtins must be a mapping")

    # Validate allowed_builtins
    for name, fn in allowed_builtins.items():
        if not isinstance(name, str):
            raise ValueError("All keys in allowed_builtins must be strings")
        if not callable(fn):
            raise ValueError(f"Value for '{name}' must be callable")

    class SafeVisitor(ast.NodeVisitor):
        allowed_nodes = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Name,
            ast.Call,
            ast.Load,
        )
        allowed_ops = (
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.Mod,
            ast.Pow,
            ast.FloorDiv,
            ast.UAdd,
            ast.USub,
        )

        def generic_visit(self, node: ast.AST):
            if not isinstance(node, self.allowed_nodes):
                raise ValueError(f"Unsafe node type {type(node).__name__}")
            super().generic_visit(node)

        def visit_BinOp(self, node: ast.BinOp):
            if not isinstance(node.op, self.allowed_ops):
                raise ValueError(f"Unsafe binary operator {type(node.op).__name__}")
            self.visit(node.left)
            self.visit(node.right)

        def visit_UnaryOp(self, node: ast.UnaryOp):
            if not isinstance(node.op, self.allowed_ops):
                raise ValueError(f"Unsafe unary operator {type(node.op).__name__}")
            self.visit(node.operand)

        def visit_Call(self, node: ast.Call):
            if not isinstance(node.func, ast.Name):
                raise ValueError("Only simple function names allowed")
            func_name = node.func.id
            if func_name not in allowed_builtins:
                raise ValueError(f"Function {func_name} not allowed")
            for arg in node.args:
                self.visit(arg)
            for kw in node.keywords:
                self.visit(kw.value)

        def visit_Name(self, node: ast.Name):
            if node.id not in allowed_builtins and isinstance(node.ctx, ast.Load):
                raise ValueError(f"Variable {node.id} not allowed")

    try:
        tree = ast.parse(expr, mode="eval")
    except SyntaxError as e:
        raise ValueError("Invalid expression") from e

    SafeVisitor().generic_visit(tree)

    def _eval(node: ast.AST) -> Any:
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        if isinstance(node, ast.Constant):
            return node.value
        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_map = {
                ast.Add: operator.add,
                ast.Sub: operator.sub,
                ast.Mult: operator.mul,
                ast.Div: operator.truediv,
                ast.FloorDiv: operator.floordiv,
                ast.Mod: operator.mod,
                ast.Pow: operator.pow,
            }
            op_func = op_map.get(type(node.op))
            if op_func is None:
                raise ValueError(f"Unsupported binary operator {type(node.op).__name__}")
            return op_func(left, right)
        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_map = {ast.UAdd: operator.pos, ast.USub: operator.neg}
            op_func = op_map.get(type(node.op))
            if op_func is None:
                raise ValueError(f"Unsupported unary operator {type(node.op).__name__}")
            return op_func(operand)
        if isinstance(node, ast.Call):
            func_name = node.func.id
            func = allowed_builtins[func_name]
            args = [_eval(arg) for arg in node.args]
            kwargs = {kw.arg: _eval(kw.value) for kw in node.keywords if kw.arg}
            return func(*args, **kwargs)
        raise TypeError(f"Unsupported node type {type(node).__name__}")

    return _eval(tree)

# Define the allowed functions
ALLOWED_BUILTINS: Mapping[str, Callable] = MappingProxyType(
    {"len": len, "int": int, "float": float, "str": str}
)

def main() -> None:
    import sys

    # Retrieve evaluation string from command line arguments
    eval_expr: Optional[str] = None
    for i, arg in enumerate(sys.argv[1:]):
        if arg == "--eval" and i + 1 < len(sys.argv) - 1:
            eval_expr = sys.argv[i + 2]
