from __init__ import redis_db
from werkzeug.security import generate_password_hash, check_password_hash
from uuid import uuid4


class User(object):
    """User management with secure Redis storage."""

    def __init__(self, username: str | None = None, password: str | None = None):
        self.id: str | None = None
        self.username: str | None = None
        self._password_hash: str | None = None
        if username is not None:
            self.set_username(username)
        if password is not None:
            self.set_password(password)

    # -------------------------------------------------------------------------
    # Input validation
    # -------------------------------------------------------------------------
    def set_username(self, username: str) -> None:
        if not isinstance(username, str):
            raise ValueError("Username must be a string")
        username = username.strip()
        if not username:
            raise ValueError("Username cannot be empty")
        if not username.isalnum():
            raise ValueError("Username must contain only alphanumeric characters")
        if len(username) > 64:
            raise ValueError("Username too long (max 64 characters)")
        self.username = username

    def set_password(self, password: str) -> None:
        if not isinstance(password, str):
            raise ValueError("Password must be a string")
        if len(password) < 8:
            raise ValueError("Password too short (minimum 8 characters)")
        if b" " in password.encode():  # disallow spaces
            raise ValueError("Password cannot contain spaces")
        self._password_hash = generate_password_hash(password)

    def check_password(self, password: str) -> bool:
        if self._password_hash is None:
            return False
        return check_password_hash(self._password_hash, password)

    # -------------------------------------------------------------------------
    # Persisting data
    # -------------------------------------------------------------------------
    def save(self) -> None:
        """Persist user to Redis with unique username and id."""
        if self.username is None:
            raise ValueError("Username not set")
        if self._password_hash is None:
            raise ValueError("Password not set")

        # Ensure username uniqueness
        username_key = f"username:{self.username}"
        if redis_db.exists(username_key):
            existing_id = redis_db.get(username_key).decode()
            if existing_id and existing_id != self.id:
                raise ValueError("Username already taken")
        else:
            # Create mapping (atomic)
            if redis_db.setnx(username_key, self.username):
                # Key created, set TTL same as user data
                redis_db.expire(username_key, 86400)

        # Determine user id
        if self.id is None:
            self.id = str(uuid4())
        user_key = f"user:{self.id}"
        data = {
            "id": self.id,
            "username": self.username,
            "pw_hash": self._password_hash,
        }
        try:
            pipeline = redis_db.pipeline()
            pipeline.hset(user_key, mapping=data)
            pipeline.expire(user_key, 86400)
            pipeline.execute()
            # Ensure username mapping points to the correct id
            redis_db.set(username_key, self.id, nx=False)
        except Exception as exc:
            raise RuntimeError("Failed to persist user data") from exc

    @classmethod
    def load(cls, username: str) -> "User | None":
        """Load user by username."""
        if not isinstance(username, str):
            raise ValueError("Username must be a string")
        username_key = f"username:{username}"
        if not redis_db.exists(username_key):
            return None
        try:
            user_id = redis_db.get(username_key).decode()
            if not user_id:
                return None
            user_key = f"user:{user_id}"
            raw = redis_db.hgetall(user_key)
            if not raw:
                return None
            user = cls()
            user.id = raw.get(b"id", b"").decode()
            user.username = raw.get(b"username", b"").decode()
            user._password_hash = raw.get(b"pw_hash", b"").decode()
            return user
        except Exception as exc:
            raise RuntimeError("Failed to load user data") from exc

    def delete(self) -> None:
        """Delete user data from Redis."""
        if self.username is None:
            raise ValueError("Username not set")
        if self.id is None:
            raise ValueError("User ID missing")
        user_key = f"user:{self.id}"
        username_key = f"username:{self.username}"
        try:
            pipeline = redis_db.pipeline()
            pipeline.delete(user_key)
            pipeline.delete(username_key)
            pipeline.execute()
        except Exception as exc:
            raise RuntimeError("Failed to delete user") from exc

    def __repr__(self) -> str:
        return f"<User id={self.id!r} username={self.username!r}>"

