    if signature_args != lambda_args:
        raise ValueError("Signature does not match lambda parameters")

    # Allowed AST node types
    allowed_nodes: Set[type] = {
        ast.Expression, ast.Lambda, ast.arguments, ast.arg, ast.Name, ast.Load,
        ast.Constant, ast.Tuple, ast.BinOp, ast.UnaryOp, ast.BoolOp,
        ast.Compare, ast.IfExp, ast.Call,
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod, ast.Pow,
        ast.UAdd, ast.USub, ast.And, ast.Or,
        ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE,
        ast.Attribute, ast.Subscript, ast.Index, ast.Slice, ast.ExtSlice,
    }

    # Functions allowed in Call nodes
    allowed_funcs: Set[str] = {
        "_mock_",
        "abs", "len", "sum", "max", "min", "round",
        "pow", "int", "float", "str", "bool", "list", "dict", "set",
    }

    for node in ast.walk(expr):
        if not isinstance(node, tuple(allowed_nodes)):
            raise ValueError(f"Disallowed construct in lambda: {type(node).__name__}")
        if isinstance(node, ast.Call):
            if not (isinstance(node.func, ast.Name) and node.func.id in allowed_funcs):
                raise ValueError(f"Disallowed function call: {getattr(node.func, 'id', '?')}")

    def _mock_proxy(*args: Any, **kwargs: Any) -> Any:
        try:
            return mock(*args, **kwargs)
        except Exception as exc:
            logging.getLogger(__name__).warning("Mock execution error: %s", exc, exc_info=True)
            raise RuntimeError("Mock execution failed") from exc

    # Prepare safe built-in functions
    safe_builtins: Dict[str, Any] = {
        name: getattr(builtins, name) for name in allowed_funcs if name != "_mock_"
    }

    safe_globals: Dict[str, Any] = {"__builtins__": safe_builtins}
    local_namespace: Dict[str, Any] = {"_mock_": _mock_proxy}

    try:
        code_obj: CodeType = compile(expr, filename="<lambda>", mode="eval")
        wrapper = eval(code_obj, safe_globals.copy(), local_namespace)
    except Exception as exc:
        logging.getLogger(__name__).warning("Failed to create wrapper: %s", exc, exc_info=True)
        raise ValueError("Failed to create wrapper with the provided signature") from exc

    return wrapper

import os
import re
import socket
import subprocess
import sys
import urllib.parse
import shutil
import ipaddress
from contextlib import contextmanager

@contextmanager
def change_dir(directory: str):
    original = os.getcwd()
    os.chdir(directory)
    try:
        yield
    finally:
        os.chdir(original)

def _get_svn_path() -> str:
    svn_path = shutil.which("svn")
    if not svn_path or not os.path.isfile(svn_path) or not os.access(svn_path, os.X_OK):
        raise RuntimeError("SVN executable not found or not executable")
    real_path = os.path.realpath(svn_path)
    if os.path.islink(real_path):
        raise RuntimeError("SVN executable is a symlink")
    if not (real_path.startswith("/usr/bin/") or real_path.startswith("/usr/local/bin/")):
        raise RuntimeError("SVN executable located in unexpected directory")
    return real_path

def _validate_host(host: str):
    if not host:
        raise ValueError("URL must contain a hostname")
    host_regex = re.compile(r"^[a-zA-Z0-9.\-]+$")
    if not host_regex.fullmatch(host):
        raise ValueError("Hostname contains invalid characters")
    try:
        for addrinfo in socket.getaddrinfo(host, None):
            ip = ipaddress.ip_address(addrinfo[4][0])
            if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_multicast:
                raise ValueError("Hostname resolves to a non-public IP address")
    except socket.gaierror:
        raise ValueError("Hostname could not be resolved")

def _validate_url(url: str):
    parsed = urllib.parse.urlparse(url)
    scheme = parsed.scheme.lower()
    if scheme != "https":
        raise ValueError("Unsupported URL scheme")
    if re.search(r"\s", url):
        raise ValueError("URL contains whitespace characters")
    _validate_host(parsed.hostname or "")
    if parsed.path:
        decoded_path = urllib.parse.unquote(parsed.path)
        if '..' in decoded_path.split('/') or re.search(r'\s', decoded_path):
            raise ValueError("URL path contains forbidden sequence '..' or whitespace")
    if parsed.query or parsed.fragment:
        raise ValueError("URL must not contain query parameters or fragment identifiers")
    return parsed

def _remove_malicious_symlinks(root: str):
    for cur_dir, dirs, files in os.walk(root):
        for name in dirs + files:
            path = os.path.join(cur_dir, name)
            if os.path.islink(path):
                link_target = os.readlink(path)
                abs_target = os.path.normpath(os.path.join(cur_dir, link_target))
                abs_target = os.path.realpath(abs_target)
                if not abs_target.startswith(root):
                    try:
                        os.unlink(path)
                    except OSError:
                        pass

def safe_svn_export(url: str, staging_folder: str, verbose: bool = False) -> bool:
    parsed_url = _validate_url(url)
    staging_folder_abs = os.path.abspath(staging_folder)
    os.makedirs(staging_folder_abs, exist_ok=True)
    svn_executable = _get_svn_path()
    cmd_list = [svn_executable, "export", parsed_url.geturl(), ".", "--force"]
    try:
        with change_dir(staging_folder_abs):
            subprocess.run(
                cmd_list,
                check=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=300,
            )
    except subprocess.CalledProcessError as exc:
        raise RuntimeError("SVN export failed") from exc
    except subprocess.TimeoutExpired as exc:
        raise RuntimeError("SVN export timed out") from exc
    _remove_malicious_symlinks(staging_folder_abs)
    if verbose:
        print(f"Successfully exported to {staging_folder_abs}", file=sys.stderr)
    return True

if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="Safe SVN export")
    parser.add_argument("url", help="HTTPS SVN repository URL")
    parser.add_argument("staging", help="Staging folder")
    parser.add_argument("-v", "--verbose", action="store_true")
    args = parser.parse_args()
    safe_svn_export(args.url, args.staging, args.verbose)

