def run_in_shell(cmd):
    """
    Execute a single, whitelisted command with strict argument validation.
    """
    if not isinstance(cmd, str) or not cmd.strip():
        raise ValueError("Command must be a non-empty string.")

    args = shlex.split(cmd, posix=(os.name != 'nt'))
    if not args:
        raise ValueError("No command to execute.")

    if len(args[1:]) > 10:
        raise ValueError("Too many arguments supplied.")

    cmd_name = args[0]
    if cmd_name not in SAFE_COMMANDS:
        raise ValueError(f"Command '{cmd_name}' is not allowed.")

    base_dir = SAFE_BASE_DIR

    for arg in args[1:]:
        if not ARG_REGEX.fullmatch(arg):
            raise ValueError(f"Unsafe argument detected: {arg}")

