            raise ValueError(f"Wildcard content not allowed: {arg}")

        if cmd_name in {"del", "copy"}:
            if any(token in arg for token in ("-R", "-rf", "--recursive", "/s", "/q", "-r")):
                raise ValueError(f"Recursive deletion not allowed: {arg}")

        safe_path_check(arg, base_dir)

