ALLOWED_COMMANDS = {"echo", "ls", "cat", "pwd"}
SAFE_BASE_DIR = "/tmp/safe_dir"

DEFAULT_ENV = {"PATH": "/usr/bin:/bin", "LANG": "C"}

def _wrap_close(writer, proc):
    writer.close()
    proc.wait()
    return proc.returncode

def _is_safe_path(path, base_dir=SAFE_BASE_DIR):
    norm_path = os.path.normpath(path)
    abs_base = os.path.abspath(base_dir)
    abs_path = os.path.abspath(os.path.join(base_dir, norm_path))
    return abs_path.startswith(abs_base) and "../../" not in norm_path

def run_cmd(cmd, buffering=1, env=None):
    if isinstance(cmd, str):
        try:
            cmd_list = shlex.split(cmd)
        except ValueError as exc:
            raise ValueError(f"could not split command: {exc}") from exc
    elif isinstance(cmd, (list, tuple)):
        cmd_list = list(cmd)
    else:
        raise TypeError("cmd must be a string or a list/tuple of strings")

    if not cmd_list:
        raise ValueError("command cannot be empty")

    for arg in cmd_list:
        if not isinstance(arg, str):
            raise TypeError("command arguments must be strings")

    cmd_name = cmd_list[0]
    if cmd_name not in ALLOWED_COMMANDS:
        raise ValueError(f"command '{cmd_name}' is not allowed")

    if cmd_name in {"cat", "ls"}:
        if len(cmd_list) < 2:
            raise ValueError(f"'{cmd_name}' requires at least one argument")
        for path in cmd_list[1:]:
            if not _is_safe_path(path):
                raise ValueError(f"unsafe path '{path}'")
    elif cmd_name == "pwd":
        if len(cmd_list) > 1:
            raise ValueError("'pwd' accepts no arguments")

    env_dict = {k: str(v) for k, v in DEFAULT_ENV.items()}
