import inspect
from typing import Any, Callable, Dict, List, Tuple, get_type_hints


class RoutineInvoker:
    """Invoker that safely executes a pair of routines."""

    # Define a whitelist of allowed routine names
    _ALLOWED_ROUTINES: List[str] = [
        "compute_surface_shortwave_down",
        "compute_surface_shortwave_up",
        "calculate_sw_down",
        "calculate_sw_up",
    ]

    def _get_method(self, name: str) -> Callable[..., Any]:
        if name not in self._ALLOWED_ROUTINES:
            raise ValueError(f"Routine name {name!r} is not allowed")
        if not hasattr(self, name):
            raise AttributeError(f"Method {name!r} not found on {self.__class__.__name__}")
        return getattr(self, name)

    def _validate_kwargs(self, method: Callable[..., Any], kwargs: Dict[str, Any]) -> Dict[str, Any]:
        signature = inspect.signature(method)
        validated = {}
        for key, value in kwargs.items():
            if key not in signature.parameters:
                raise ValueError(f"Unexpected parameter {key!r} for method {method.__name__}")
            param = signature.parameters[key]
            anno = param.annotation
            if anno is inspect._empty:
                anno = Any
            if anno is Any:
                validated[key] = value
                continue
            # Handle basic type annotations
            if isinstance(anno, type):
                if not isinstance(value, anno):
                    # allow coercion for int and float when value is a number string
                    if anno in (int, float) and isinstance(value, str):
                        try:
                            value = anno(value)
                        except ValueError:
                            raise TypeError(f"Parameter {key!r} must be {anno.__name__}")
                    else:
                        raise TypeError(f"Parameter {key!r} must be {anno.__name__}")
            else:
                # For more complex annotations, attempt cooperative type checking
                if not isinstance(value, anno):
                    raise TypeError(f"Parameter {key!r} does not match annotation {anno}")
            validated[key] = value
        return validated

    def execute(self,
                routine_down: str,
                routine_up: str,
                **kwargs: Any) -> Dict[str, float]:
        """Execute a pair of approved routines with validated arguments."""
        if not routine_down.isidentifier() or not routine_up.isidentifier():
            raise ValueError("Routine names must be valid identifiers")

        method_down = self._get_method(routine_down)
        method_up = self._get_method(routine_up)

        # Validate and sanitize keyword arguments for each method
        kw_down = self._validate_kwargs(method_down, kwargs)
        kw_up = self._validate_kwargs(method_up, kwargs)

        try:
            sw_down = method_down(**kw_down)
        except Exception as exc:
            raise RuntimeError("Error computing surface shortwave downwards radiation") from None

        try:
            sw_up = method_up(**kw_up)
        except Exception as exc:
            raise RuntimeError("Error computing surface upward flux") from None

        net_shortwave = sw_down - sw_up

        return {
            "sw_down": sw_down,
            "sw_up": sw_up,
            "net_shortwave": net_shortwave,
        }

