SAFE_ENV = {k: v for k, v in os.environ.items() if k in ("HOME", "PATH", "LANG", "LC_ALL")}
SAFE_ENV["PATH"] = "/usr/bin:/bin"

def cleanup_temp_dir():
    try:
        os.rmdir(SAFE_BASE_DIR)
    except Exception:
        pass

atexit.register(cleanup_temp_dir)

