    level=logging.INFO,
    format="%(asctime)s %(levelname)s [%(lineno)d] %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)

def is_within_base(path: str, base: str) -> bool:
    try:
        real_path = os.path.realpath(path)
        base_path = os.path.realpath(base)
    except Exception:
        return False
    try:
        return os.path.commonpath([real_path, base_path]) == base_path
    except ValueError:  # paths on different drives (unlikely on Unix)
        return False

def resolve_path(arg: str) -> str:
    if os.path.isabs(arg):
        return os.path.realpath(arg)
    return os.path.realpath(os.path.join(SAFE_BASE_DIR, arg))

