    cmd_name = cmd_args[0]
    if cmd_name not in ALLOWED_COMMANDS:
        return False, f"Command '{cmd_name}' not permitted."

    # Replace command with absolute path
    cmd_args[0] = ALLOWED_COMMANDS[cmd_name]

