        if len(cmd_args) != 2:
            return False, "cat requires exactly one file argument."
        real_file = os.path.realpath(cmd_args[1])
        if real_file not in WHITELISTED_FILES:
            return False, f"Access to '{cmd_args[1]}' is denied."
    elif cmd_name == "ls":
        if len(cmd_args) < 2:
            return False, "ls requires at least one path argument."
        for arg in cmd_args[1:]:
