from urllib.parse import urlparse

def submit_login_form(user, form):
    # Directly use the raw credentials; avoid unnecessary escaping
    form['username'] = user.username
    form['password'] = user.password

    # Validate and include the CSRF token if present
    csrf_field = form.fields.get('csrf_token')
    if csrf_field:
        csrf_value = csrf_field.value
        if not csrf_value:
            raise ValueError('CSRF token is missing or empty')
        form['csrf_token'] = csrf_value

    # Ensure the form action uses HTTPS
    action_url = form.get_action()
    if urlparse(action_url).scheme != 'https':
        raise RuntimeError('Form submission must use HTTPS')

    # Submit the form and handle failures securely
    try:
        login_response = form.submit()
    except Exception as exc:
        # Do not expose the raw exception; rethrow with a generic message
        raise RuntimeError('Login form submission failed') from exc

    # Verify a successful response beyond status code
    if login_response.status_code != 200 or b'Login failed' in login_response.text.encode():
        raise RuntimeError('Login was not successful')

    # Confirm that a legitimate session cookie was issued
    session_cookie_names = {'sessionid', 'sid', 'django_session'}
    if not any(c.key.lower() in session_cookie_names for c in login_response.cookies):
        raise RuntimeError('Expected session cookie not found')

    return login_response

