class Scheduler:
    def __init__(self, state_path: str, state_dir: str, state_version: str):
        self._state_path = state_path
        self._state_dir = state_dir
        self._state_version = state_version
        self._state: list[dict] = []
        self._last_run: float = 0.0

    def _validate_task(self, task):
        if not isinstance(task, dict):
            return False
        required_keys = {"name", "schedule", "params"}
        if not required_keys.issubset(task.keys()):
            return False
        if not isinstance(task["name"], str):
            return False
        if not isinstance(task["schedule"], str):
            return False
        if not isinstance(task["params"], dict):
            return False
        for val in task["params"].values():
            if not isinstance(val, (str, int, float, bool, type(None))):
                return False
        return True

    def load_state(self):
        try:
            abs_path = Path(self._state_path).resolve()
            base = Path(self._state_dir).resolve()
            if not str(abs_path).startswith(str(base)):
                logger.warning("Disallowed path: %s", self._state_path)
                return None
            if not abs_path.is_file():
                logger.warning("State file does not exist: %s", abs_path)
                return None
        except Exception as e:
            logger.warning("Path validation error: %s", e)
            return None

        try:
            with abs_path.open("r", encoding="utf-8") as fobj:
                loaded_state = json.load(fobj)
        except (json.JSONDecodeError, ValueError) as e:
            logger.warning("Failed to parse scheduler JSON state: %s", e)
            return None
        except Exception as e:
            logger.warning("Unexpected error while loading state: %s", e)
            return None

        if not isinstance(loaded_state, dict):
            logger.warning(
                "Invalid state format: expected dict, got %s",
                type(loaded_state).__name__,
            )
            return None

        if loaded_state.get("version") != self._state_version:
            logger.warning(
                "State version mismatch: expected %s, got %s",
                self._state_version,
                loaded_state.get("version"),
            )
            return None

        expected_keys = {"tasks": list, "last_run": (float, int)}
        for key, typ in expected_keys.items():
            if key not in loaded_state:
                logger.warning("Missing key %s in state", key)
                return None
            if not isinstance(loaded_state[key], typ):
                logger.warning(
                    "Invalid type for key %s: expected %s, got %s",
                    key,
                    (
                        typ.__name__
                        if hasattr(typ, "__name__")
                        else str(typ)
