TOKEN_REGEX = re.compile(r"[A-Za-z0-9@._\-\#\+=]+", re.ASCII)
PBKDF2_ITERATIONS = 100_000


def _is_valid_token(token: str) -> bool:
    return bool(TOKEN_REGEX.fullmatch(token))


def _safe_compare(expected: str, actual: str) -> bool:
    return hmac.compare_digest(expected, actual)


def _parse_rpcauth(rpcauth_str: str):
    pattern = r"^rpcauth=([a-z]+):([0-9a-f]{64})\$([0-9a-f]{32})$"
    match = re.fullmatch(pattern, rpcauth_str)
    if not match:
        raise ValueError("Invalid rpcauth format")
    return match.group(1), match.group(2), match.group(3)


def verify_rpcauth_configuration(url: str, rpcauth_str: str) -> bool:
    try:
        parsed_url = urlparse(url)
        username = parsed_url.username
        password = parsed_url.password
        if not username or not password:
            raise ValueError
        if not _is_valid_token(username) or not _is_valid_token(password):
            raise ValueError
        _, expected_hash, salt = _parse_rpcauth(rpcauth_str)
        credential_bytes = f"{username}:{password}".encode("utf-8")
