_MAX_GB = Decimal(10240)  # 10 TB expressed in GB


def to_coraid_kb(value: Union[str, int, float, Decimal]) -> int:
    """
    Convert gigabytes to kilobytes for Coraid volume naming.

    Returns an integer number of kilobytes. Raises ValueError for
    nonânumeric, nonâpositive, or overly large values.
    """
    try:
        dec_value = Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError):
        logger.error("Invalid numeric value for volume size.")
        raise ValueError("Volume size must be a numeric value") from None

    if dec_value <= 0:
        logger.error("Nonâpositive volume size provided.")
        raise ValueError("Volume size must be greater than zero")

    if dec_value > _MAX_GB:
        logger.error("Volume size exceeds maximum allowed (%s GB).", _MAX_GB)
        raise ValueError(f"Volume size must not exceed {_MAX_GB} GB")

    try:
        kb = int(dec_value * Decimal(1024))
    except (OverflowError, ValueError):
        logger.error("Error converting volume size to kilobytes.")
        raise ValueError("Volume size too large for conversion") from None

