    except ValueError:
        raise ValueError("Invalid SAN IP address in configuration")

    san_login = config["san_login"]
    if not isinstance(san_login, str):
        raise ValueError("SAN login must be a string")
    if len(san_login) > 64:
        raise ValueError("SAN login exceeds maximum length of 64 characters")
    if not re.fullmatch(r"[A-Za-z0-9_]+", san_login):
        raise ValueError("SAN login contains unsafe characters")

    pool_name = config["storage_vnx_pool_name"]
    if not isinstance(pool_name, str):
        raise ValueError("Storage pool name must be a string")
    if len(pool_name) > 64:
        raise ValueError("Storage pool name exceeds maximum length of 64 characters")
    if not re.fullmatch(r"[A-Za-z0-9_\-]+", pool_name):
        raise ValueError("Storage pool name contains unsafe characters")

    nav_path = Path(config["naviseccli_path"])
    if not nav_path.is_absolute():
        raise ValueError("naviseccli_path must be an absolute path")

    allowed_root = Path("/usr/local/bin")
    try:
        resolved_path = nav_path.resolve(strict=True)
    except FileNotFoundError as exc:
        raise ValueError(f"naviseccli_path does not exist: {exc}") from None

    try:
        resolved_path.relative_to(allowed_root)
    except ValueError:
        raise ValueError("naviseccli_path is not within the allowed directory")

    if not resolved_path.is_file():
        raise ValueError("naviseccli_path must be a file")

    mode = resolved_path.stat().st_mode
    if not (mode & stat.S_IEXEC):
        raise ValueError("naviseccli_path must be executable")


class NavisecCLI:
    def __init__(self, configuration: Dict[str, Any]) -> None:
        _validate_configuration(configuration)
        self.configuration = configuration
        self._cli_path_obj = Path(self.configuration["naviseccli_path"]).resolve(strict=True)
        stat_result = self._cli_path_obj.stat()
        self._cli_initial_inode = stat_result.st_ino
        self._cli_initial_dev = stat_result.st_dev
        self._allowed_root = Path("/usr/local/bin")

    def _build_safe_cli(self) -> Callable[..., str]:
        def _safe_cli_command(*args: str) -> str:
            if not all(isinstance(arg, str) for arg in args):
                raise TypeError("All CLI arguments must be strings")

            try:
                current_stat = self._cli_path_obj.stat()
            except FileNotFoundError:
                raise RuntimeError("naviseccli binary no longer exists")

            if (current_stat.st_ino != self._cli_initial_inode or
                    current_stat.st_dev != self._cli_initial_dev):
                raise RuntimeError("naviseccli binary has changed since initialization")

            if not (current_stat.st_mode & stat.S_IEXEC):
                raise RuntimeError("naviseccli binary is no longer executable")

            cmd = [str(self._cli_path_obj)] + list(args)
            try:
                result = subprocess.run(
                    cmd,
                    capture_output=True,
                    text=True,
                    check=True,
                    timeout=5,
                )
                return result.stdout.strip()
            except subprocess.TimeoutExpired:
                raise RuntimeError("CLI command timed out")
            except subprocess.CalledProcessError as exc:
                msg = f"CLI command failed: {exc.stderr.strip() or exc}"
                raise RuntimeError(msg)

        return _safe_cli_command

    safe_cli = property(_build_safe_cli)

