import ast
from pathlib import Path
import re
from typing import Dict

def get_package_version() -> Dict[str, str]:
    """
    Retrieve the package version from the project's version.py file.

    Returns:
        A dictionary containing the key "__version__" mapped to the version string.

    Raises:
        RuntimeError: If the version cannot be retrieved due to a missing file,
                      permission issues, decoding errors, or parsing errors.
    """
    # Resolve the path to the version file relative to this script
    try:
        base_path = Path(__file__).resolve().parent.parent
    except NameError:
        # Fallback in environments where __file__ is undefined
        base_path = Path.cwd().resolve()

    version_file = (
        base_path
        / "src"
        / "openalea"
        / "container"
        / "version.py"
    )

    if not version_file.is_file():
        raise RuntimeError(f"Version file not found: {version_file}")

    try:
        content: str = version_file.read_text(encoding="utf-8")
    except (PermissionError, OSError, UnicodeDecodeError) as exc:
        raise RuntimeError(f"Unable to read version file: {version_file}") from exc

    # Quick regex extraction first
    ver_pattern = re.compile(r"(__version__|VERSION)\s*=\s*['"]([^'"]+)['"]")
    match = ver_pattern.search(content)
    if match:
        return {"__version__": match.group(2)}

    # Fallback to AST parsing if regex failed
    try:
        tree = ast.parse(content, filename=str(version_file))
    except SyntaxError as exc:
        raise RuntimeError(f"Syntax error while parsing {version_file}") from exc

    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id in ("__version__", "VERSION"):
                    if isinstance(node.value, ast.Constant) and isinstance(node.value.value, str):
                        return {"__version__": node.value.value}
                    elif hasattr(ast, "Str") and isinstance(node.value, ast.Str):  # pragma: no cover
                        return {"__version__": node.value.s}

    # If no version was found
    raise RuntimeError("Version string not found in version file")

if __name__ == "__main__":
    print(get_package_version())

