import os
from pathlib import Path


def compute_file_hash(filename, hash_function, base_dir=None):
    if not isinstance(filename, (str, bytes, os.PathLike)):
        raise TypeError('filename must be a string, bytes, or path-like object')
    if not hasattr(hash_function, 'update') or not hasattr(hash_function, 'hexdigest'):
        raise TypeError('hash_function must provide update and hexdigest methods')
    if not hasattr(hash_function, 'name') or not isinstance(hash_function.name, str):
        raise TypeError('hash_function must provide a name attribute')
    if hash_function.name.lower() not in {'sha256', 'sha512'}:
        raise ValueError('hash_function must use a secure hash algorithm (sha256 or sha512)')
    if base_dir is None:
        base_dir = Path.cwd()
    else:
        base_dir = Path(base_dir).resolve(strict=True)
    path = Path(filename).resolve(strict=True)
    try:
        path.relative_to(base_dir)
    except ValueError:
        raise ValueError('File path is not within the expected base directory')
    if not path.is_file():
        raise ValueError(f'{filename} is not a regular file')
    try:
        with path.open('rb') as f:
            for block in iter(lambda: f.read(8192), b''):
                hash_function.update(block)
    except OSError as err:
        raise OSError(f'Error reading file {filename}') from err
    return hash_function.hexdigest()

