# JSON serializer/deserializer for trusted data
class SafeJSON:
    @staticmethod
    def dumps(obj: Any) -> str:
        if isinstance(obj, (dict, list, tuple, set, int, float, str, bool, type(None))):
            # Convert tuples and sets to lists for JSON
            if isinstance(obj, tuple):
                obj = list(obj)
            if isinstance(obj, set):
                obj = list(obj)
            return json.dumps(obj)
        raise TypeError(f"Object of type {type(obj).__name__} is not JSON serializable")

    @staticmethod
    def loads(data: Union[str, bytes]) -> Any:
        if isinstance(data, (bytes, bytearray)):
            data = data.decode("utf-8")
        if not isinstance(data, str):
            raise TypeError("data must be a string or bytes")
        obj = json.loads(data)
        # Convert lists back to tuples and sets if needed
        return obj

def restricted_loads(data: Union[bytes, bytearray]) -> Any:
    """
    Safely load JSON data, ensuring it contains only basic data types.
    """
    if not isinstance(data, (bytes, bytearray)):
        raise TypeError("data must be bytes or bytearray")
    if not data:
        raise ValueError("data must not be empty")
    return SafeJSON.loads(data)

def sanitize_and_validate(defn: Any, bstr: Union[bytes, bytearray]) -> Any:
    """
    Load data, verify integrity, and return a separate instance.
    """
    if not isinstance(bstr, (bytes, bytearray)):
        raise TypeError("bstr must be bytes-like")
    if not bstr:
        raise ValueError("bstr must not be empty")

    try:
        recovered = restricted_loads(bstr)
    except Exception as exc:
        raise ValueError(f"Deserialization failed: {exc}") from exc

    if recovered != defn:
        raise AssertionError("Recovered object does not equal the original")

    # Ensure recovered is a distinct instance (mutable types)
    if isinstance(recovered, (dict, list, set, tuple)):
        if recovered is defn:
            raise AssertionError("Recovered object should be a distinct instance")

    # Verify type match
    if type(recovered) is not type(defn):
        raise AssertionError("Type mismatch between recovered object and original")

    # Deep copy for safe mutation (only if mutable)
    if isinstance(recovered, (dict, list, set)):
        try:
            modified = copy.deepcopy(recovered)
        except Exception as exc:
            raise RuntimeError(f"Deep copy failed: {exc}") from exc
        # Example modification logic
