ALLOWED_BIN_DIR = pathlib.Path("/opt/genomics/bin").resolve()
ALLOWED_CMDS = {"mapper"}
ALLOWED_FILE_BASE = pathlib.Path("/opt/genomics/data").resolve()

def _validate_file(path: str, purpose: str) -> pathlib.Path:
    p = pathlib.Path(path).resolve()
    if not p.is_file():
        raise FileNotFoundError(f"{purpose} file not found: {p}")
    if not str(p).startswith(str(ALLOWED_FILE_BASE)):
        raise PermissionError(f"{purpose} file outside allowed directory: {p}")
    return p

def _validate_output(path: str) -> pathlib.Path:
    p = pathlib.Path(path).resolve()
    if p.is_dir():
        raise IsADirectoryError(f"Output path is a directory: {p}")
    if not str(p.parent).startswith(str(ALLOWED_FILE_BASE)):
        raise PermissionError(f"Output directory outside allowed base: {p.parent}")
    return p

def _validate_binary(cmd: str) -> tuple[pathlib.Path, list[str]]:
    parts = shlex.split(cmd, posix=True)
    if not parts:
        raise ValueError("Empty alignment command")
    exe = pathlib.Path(parts[0]).resolve()
    if not exe.is_file() or not os.access(str(exe), os.X_OK):
        raise FileNotFoundError(f"Executable not found or not executable: {exe}")
    if exe.parent != ALLOWED_BIN_DIR:
        raise PermissionError(f"Executable {exe} outside allowed bin directory")
    if exe.name not in ALLOWED_CMDS:
        raise ValueError(f"Executable {exe.name} not in allowed command list")
    disallowed = {"&", "|", ";", "$", "`", """, "\"}
    for arg in parts[1:]:
        if any(c in arg for c in disallowed):
            raise ValueError(f"Suspicious argument in command: {arg}")
    return exe, parts[1:]

def _mask_paths(cmd_list: list[str]) -> str:
    masked = []
    for part in cmd_list:
        if pathlib.Path(part).is_file():
            masked.append("FILE")
        else:
            masked.append(part)
    return " ".join(masked)

def parse_options() -> Namespace:
    parser = ArgumentParser(description="Genome mapper executor")
    parser.add_argument("--ref", required=True, help="Reference file path")
    parser.add_argument("--input1", required=True, help="Input file path")
    parser.add_argument("--output", required=True, help="Output file path")
    parser.add_argument("--aligning-cmd", required=True, help="Alignment command")
    return parser.parse_args()

def main():
    opts = parse_options()
    try:
        ref_path = _validate_file(opts.ref, "Reference")
        input_path = _validate_file(opts.input1, "Input")
        output_path = _validate_output(opts.output)
        ref_inode = ref_path.stat().st_ino
        input_inode = input_path.stat().st_ino
        exe_path, cmd_args = _validate_binary(opts.aligning_cmd)
        exe_inode = exe_path.stat().st_ino
        cmd_parts = [str(exe_path)] + cmd_args + [
