def validate_key(key: str) -> None:
    validate_name(key, "encryption key")
    if len(key) < 16:
        raise ValueError("Encryption key must be at least 16 characters long")

def validate_output_file(out_path: pathlib.Path, base_dir: pathlib.Path) -> pathlib.Path:
    if out_path.is_absolute():
        raise ValueError("Output file path must be relative")
    resolved = (base_dir / out_path).resolve()
    try:
        if not resolved.is_relative_to(base_dir.resolve()):
            raise ValueError("Output file must be within the output directory")
    except AttributeError:
        if not str(resolved).startswith(str(base_dir.resolve())):
            raise ValueError("Output file must be within the output directory")
    resolved.parent.mkdir(parents=True, exist_ok=True)
    return resolved

def validate_extract_dir(extract_dir: pathlib.Path, sandbox_root: pathlib.Path) -> pathlib.Path:
    if not extract_dir.is_dir():
        raise ValueError("extract_destination_path must be an existing directory")
    if extract_dir.is_symlink():
        raise ValueError("extract_destination_path must not be a symlink")
    resolved = extract_dir.resolve()
    try:
        if not resolved.is_relative_to(sandbox_root.resolve()):
            raise ValueError("extract_destination_path must reside in the sandbox")
    except AttributeError:
        if not str(resolved).startswith(str(sandbox_root.resolve())):
