import ast
import logging
import multiprocessing as mp
import os
import resource
import math
import time
from typing import Any, Callable, Dict, Optional

# Allowed built-in names and attributes for sandboxed execution
_ALLOWED_BUILTINS = {}
_ALLOWED_NAMES = {"math", "time", "process", "True", "False", "None"}
_ALLOWED_MATH_FUNCS = {
    "sqrt",
    "log",
    "log10",
    "exp",
    "sin",
    "cos",
    "tan",
    "ceil",
    "floor",
    "fabs",
}
_ALLOWED_TIME_FUNCS = {"time", "sleep"}


def _validate_ast(node: ast.AST) -> bool:
    for child in ast.iter_child_nodes(node):
        if isinstance(child, (ast.Import, ast.ImportFrom)):
            return False
        if isinstance(child, (ast.Global, ast.Nonlocal)):
            return False
        if isinstance(child, ast.Call):
            if (
                isinstance(child.func, ast.Name)
                and child.func.id in {"exec", "eval", "compile"}
            ):
                return False
        if isinstance(child, ast.Attribute):
            if isinstance(child.value, ast.Name) and child.value.id not in (
                "math",
                "time",
            ):
                return False
        if isinstance(child, ast.Name):
            if child.id not in _ALLOWED_NAMES:
                return False
        if isinstance(child, ast.Attribute):
            if isinstance(child.value, ast.Name):
                if child.value.id == "math" and child.attr not in _ALLOWED_MATH_FUNCS:
                    return False
                if child.value.id == "time" and child.attr not in _ALLOWED_TIME_FUNCS:
                    return False
        if not _validate_ast(child):
            return False
    return True


def _is_safe_path(target: str, root: str) -> bool:
    try:
        target_real = os.path.realpath(target)
        root_real = os.path.realpath(root)
    except Exception:
        return False
    return os.path.commonpath([target_real, root_real]) == root_real


def _sandbox_worker(
    compiled_code: Any,
    base: Dict[str, Any],
    queue: mp.Queue,
) -> None:
    try:
        resource.setrlimit(resource.RLIMIT_CPU, (1, 1))
        resource.setrlimit(
            resource.RLIMIT_AS, (50 * 1024 * 1024, 50 * 1024 * 1024)
        )

        sandbox_globals: Dict[str, Any] = {"__builtins__": {}}
        sandbox_globals.update({"math": math, "time": time})

        exec(compiled_code, sandbox_globals)

        process_func: Optional[Callable[[Dict[str, Any]], Any]] = sandbox_globals.get(
            "process"
        )
        result: Optional[Dict[str, Any]] = None
        if callable(process_func):
            candidate = process_func(base)
            if isinstance(candidate, dict):
                sanitized: Dict[str, Any] = {}
                for k, v in candidate.items():
                    if isinstance(k, str) and isinstance(
                        v,
                        (int,
                         float,
                         str,
                         bool),
                    ):
                        sanitized[k] = v
                result = sanitized

        queue.put(("ok", result))
    except Exception as exc:
        queue.put(("error", str(exc)))


def _compile_and_validate(source: str) -> Any:
    try:
        tree = ast.parse(source, mode="exec")
    except SyntaxError as se:
        raise ValueError(f"Syntax error: {se}") from se
    if not _validate_ast(tree):
        raise ValueError("Disallowed code detected")
    try:
        return compile(source, filename="<extension>", mode="exec")
    except Exception as exc:
        raise ValueError(f"Compilation failed: {exc}") from exc


def run_environment_extension(
    base: Dict[str, Any],
    extension_path: str,
    root_dir: str,
    timeout: float = 2.0,
) -> Dict[str, Any]:
    if not isinstance(extension_path, str) or not isinstance(root_dir, str):
        logging.error("Invalid path arguments")
        return base

    if not _is_safe_path(extension_path, root_dir):
        logging.warning(
            "Extension path %s is outside the designated root %s; aborting execution.",
            extension_path,
            root_dir,
        )
        return base

    try:
        with open(extension_path, "r", encoding="utf-8") as fp:
            extension_source = fp.read()
    except Exception as exc:
        logging.error("Failed to read extension file %s: %s", extension_path, exc)
        return base

    try:
        compiled = _compile_and_validate(extension_source)
    except ValueError as ve:
        logging.error(
            "Validation or compilation error in extension '%s': %s",
            extension_path,
            ve,
        )
        return base

    result_queue: mp.Queue = mp.Queue()
    proc = mp.Process(
        target=_sandbox_worker,
        args=(compiled, base, result_queue),
        daemon=True,
    )
    proc.start()
    proc.join(timeout)

    if proc.is_alive():
        proc.terminate()
        proc.join()
        logging.error("Extension execution timed out after %.1f seconds", timeout)
        return base

    try:
        status, payload = result_queue.get_nowait()
    except Exception:
        logging.error("No result returned from extension execution.")
        return base

    if status == "ok" and isinstance(payload, dict):
        base.update(payload)
    elif status == "error":
        logging.error("Error executing environment extension: %s", payload)

    return base

