IDENTIFIER_RE = re.compile(r"^[A-Z0-9_]+$")

def safe_url(url: str) -> bool:
    try:
        parts = urllib.parse.urlparse(url)
        if parts.scheme != "https":
            return False
        if parts.netloc != "ftp-trace.ncbi.nlm.nih.gov":
            return False
        if ".." in parts.path or parts.path.startswith("/"):
            return False
        return True
    except Exception:
        return False

def is_response_safe(resp_url: str, expected_url: str) -> bool:
    try:
        parts_resp = urllib.parse.urlparse(resp_url)
        parts_exp = urllib.parse.urlparse(expected_url)
        if parts_resp.scheme != "https":
            return False
        if parts_resp.netloc != "ftp-trace.ncbi.nlm.nih.gov":
            return False
        if parts_resp.path != parts_exp.path:
            return False
        return True
    except Exception:
        return False

def download_sra(srr: str, srx: str, dst_path: pathlib.Path) -> bool:
    url = (
        f"https://ftp-trace.ncbi.nlm.nih.gov/sra/sra-instant/reads/ByExp/sra/"
        f"{srx[:3]}/{srx[:6]}/{srx}/{srr}/{srr}.sra"
    )
    if not safe_url(url):
        logger.error(f"URL validation failed for {srr}: {url}")
        return False
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "SecureDownloader/1.0"})
        with urllib.request.urlopen(req, timeout=120) as resp:
            final_url = resp.geturl()
            if not is_response_safe(final_url, url):
                logger.error(
                    f"Unexpected final URL for {srr}. Expected {url}, got {final_url}"
                )
                return False
            with dst_path.open("wb") as out_file:
                shutil.copyfileobj(resp, out_file)
        if dst_path.stat().st_size == 0:
            logger.error(f"Downloaded file is empty for {srr}")
            dst_path.unlink(missing_ok=True)
            return False
        return True
    except urllib.error.HTTPError as e:
        logger.error(f"HTTP error {e.code} for {srr} at {url}")
        return False
    except urllib.error.URLError as e:
        logger.error(f"URL error for {srr} at {url}: {e}")
        return False
    except Exception as exc:
        logger.error(f"Could not download {url} for {srr}: {exc}")
        return False

def convert_sra_to_fastq(sra_path: pathlib.Path, out_dir: pathlib.Path, srr: str) -> bool:
    if not sra_path.is_file() or sra_path.suffix != ".sra":
        logger.error(f"Invalid SRA path: {sra_path}")
        return False
    fasterq = shutil.which("fasterq-dump")
    if not fasterq:
        logger.error("fasterq-dump not found in PATH")
        return False
    cmd = [
        fasterq,
        "-O",
        str(out_dir),
        "--split-files",
        "--outfile",
        srr,
        str(sra_path),
    ]
    try:
        result = subprocess.run(
            cmd,
            check=True,
            capture_output=True,
            text=True,
            env={"PATH": "/usr/local/bin:/usr/bin:/bin"},
        )
        if result.stdout:
            logger.debug(result.stdout)
        return True
    except subprocess.CalledProcessError as exc:
        logger.error(f"Conversion failed for {srr}: {exc.stderr}")
        return False
    except Exception as exc:
        logger.error(f"Unexpected error during conversion for {srr}: {exc}")
        return False

for srr, srx in FILES:
    if not IDENTIFIER_RE.fullmatch(srr) or not IDENTIFIER_RE.fullmatch(srx):
        logger.warning(f"Skipping invalid identifiers: srr={srr} srx={srx}")
        continue

    out_fastq1 = OUT_DIR / f"{srr}_1.fastq"
    out_fastq2 = OUT_DIR / f"{srr}_2.fastq"

    if out_fastq1.exists() and out_fastq2.exists():
