    if not (out_fastq1.exists() and out_fastq2.exists()):
        logger.error(f"FASTQ files missing after conversion for {srr}")
    else:
        logger.info(f"Processed {srr} successfully.")

import json
import logging

logger = logging.getLogger(__name__)

def decode(encoded_str, encoding_keys: bool = False, max_size: int = 1_048_576, max_depth: int = 512, backend=json) -> object:
    if not isinstance(encoded_str, (str, bytes)):
        raise TypeError("encoded data must be a string or bytes")
    if isinstance(encoded_str, bytes):
        try:
            encoded_str = encoded_str.decode("utf-8")
        except UnicodeDecodeError as exc:
            raise ValueError("Encoded bytes are not valid UTF-8") from exc
    if len(encoded_str) > max_size:
        raise ValueError("Encoded data exceeds maximum allowed size")
    if backend is not json:
        raise ValueError("Unsupported serialization backend")
    try:
        decoded = backend.loads(encoded_str)
    except Exception as exc:
        raise ValueError("Invalid input for decoding") from exc
    if encoding_keys:
        def _decode_keys(obj, depth: int = 0):
            if depth > max_depth:
                raise ValueError("Maximum decoding depth exceeded")
            if isinstance(obj, dict):
                new_dict = {}
                for key, val in obj.items():
                    try:
                        new_key = json.loads(json.dumps(key))
                    except Exception as exc:
                        logger.warning("Failed to decode key %r: %s", key, exc)
                        new_key = key
                    new_dict[new_key] = _decode_keys(val, depth + 1)
                return new_dict
            if isinstance(obj, list):
                return [_decode_keys(item, depth + 1) for item in obj]
            return obj
        decoded = _decode_keys(decoded)
    return decoded

