class BookPlayer:
    """Handles playback of books with secure path validation and database cleanup."""

    def __init__(self, books_root, queue, db, logger=None):
        self.books_root = books_root
        self.queue = list(queue)
        self.db = db
        self.logger = logger or logging.getLogger(__name__)
        self.player = _MockPlayer()  # Replace with actual player implementation
        self.current_book_id = None

    def run(self):
        """Main playback loop."""
        while True:
            if getattr(self.player, "is_playing", False):
                self.cleanup_progress()
                continue
            else:
                book_path = self.select_next_book()
                if not book_path:
                    break
                try:
                    safe_path = self.sanitize_path(book_path)
                    self.player.load(str(safe_path))
                    self.player.play()
                    self.on_playing()
                except OSError as e:
                    self.logger.error(f"Failed to play book at {book_path}: {e}")
                    continue

    def cleanup_progress(self):
        """Remove the current book's progress from the database."""
        if hasattr(self, "current_book_id") and self.current_book_id is not None:
            try:
                book_id = int(self.current_book_id)
                self.db.delete(book_id)
                self.logger.debug(f"Progress for book {book_id} cleared")
            except Exception as db_err:
                self.logger.warning(f"DB cleanup failed: {db_err}")

    def sanitize_path(self, path):
        """
        Resolve and validate that the path is within the allowed books directory.
        Raises ValueError if path is outside the permitted area.
        """
        allowed_dir = Path(self.books_root).resolve()
        candidate = Path(path).resolve()
        if hasattr(candidate, "is_relative_to"):
            if not candidate.is_relative_to(allowed_dir):
                raise ValueError("Attempt to access disallowed path")
        else:
            if candidate.parts[: len(allowed_dir.parts)] != allowed_dir.parts:
                raise ValueError("Attempt to access disallowed path")
        return candidate

    def select_next_book(self):
        """Retrieve the next book's file path from the queue. Return None if empty."""
        try:
            return self.queue.pop(0)
        except IndexError:
            return None

    def on_playing(self):
        """Update internal state or UI when a book is playing."""
        try:
            book_name = getattr(self.player, "current_book", "")
            if book_name:
                safe_name = Path(book_name).name
                self.logger.info(f"Playing book: {safe_name}")
            else:
                self.logger.warning("Player has no current_book attribute")
        except Exception as e:
            self.logger.warning(f"Error logging current book: {e}")


