import os
import sys
import hashlib
import logging
from pathlib import Path

logging.basicConfig(level=logging.ERROR, format='%(levelname)s: %(message)s')
log = logging.getLogger(__name__)

def get_directory(path_str):
    """
    Validate that the supplied path is an existing, nonâsymlink directory.
    Returns the resolved absolute Path.
    """
    path = Path(path_str).expanduser()
    if not path.exists():
        log.error(f"{path} does not exist!")
        sys.exit(1)
    if path.is_symlink():
        log.error(f"{path} is a symbolic link, which is not allowed.")
        sys.exit(1)
    # Resolve to an absolute path after symlink check
    path = path.resolve()
    if not path.is_dir():
        log.error(f"{path} is not a valid directory!")
        sys.exit(1)
    return path

def compute_hash(file_path):
    """
    Compute and return the SHA-256 hash of the given file.
    Raises TypeError or FileNotFoundError for invalid input.
    Returns None on read errors.
    """
    if not isinstance(file_path, (str, Path)):
        raise TypeError("file_path must be a string or PathLike object")
    path_obj = Path(file_path).resolve()
    if not path_obj.is_file():
        raise FileNotFoundError(f"{path_obj} is not a regular file")
    hash_func = hashlib.sha256()
    try:
        with path_obj.open("rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                hash_func.update(chunk)
    except (IOError, OSError) as exc:
        log.error(f"Error reading file {path_obj}: {exc}")
        return None
    return hash_func.hexdigest()

def main():
    if len(sys.argv) != 3:
        print(f"Usage: {sys.argv[0]} <directory1> <directory2>", file=sys.stderr)
        sys.exit(1)

    dir1 = get_directory(sys.argv[1])
    dir2 = get_directory(sys.argv[2])

    for base_dir in (dir1, dir2):
        for root, _, files in os.walk(base_dir, followlinks=False):
            for name in files:
                file_path = Path(root) / name
                digest = compute_hash(file_path)
                if digest:
                    try:
                        rel_path = file_path.relative_to(base_dir)
                    except ValueError:
                        # In case the file is outside the base directory, skip it
                        continue
                    print(f"{rel_path}: {digest}")

if __name__ == "__main__":
