APPROVED_ROOT = pathlib.Path.cwd().resolve()

def is_within_approved_dir(path: pathlib.Path) -> bool:
    try:
        path = path.resolve(strict=True)
        path.relative_to(APPROVED_ROOT)
        return True
    except (FileNotFoundError, ValueError):
        return False

def get_hg_executable() -> str:
    hg_path = shutil.which("hg")
    if not hg_path:
        raise RuntimeError("Mercurial executable 'hg' not found in PATH")
    # Ensure the resolved path actually points to a Mercurial executable
    if not os.path.isfile(hg_path) or not os.access(hg_path, os.X_OK):
        raise RuntimeError(f"Resolved path {hg_path} is not an executable")
    return hg_path

def get_hg_log(cset):
    if not isinstance(cset, (str, int)):
        raise ValueError("Revision identifier must be string or integer")
    cset_str = str(cset)
    if not cset_str.isdigit():
        raise ValueError("Revision identifier must be numeric")
    cmd = [
        get_hg_executable(),
        "log",
        "-r",
        cset_str,
        "--template",
        "{tags}
{date|date}
{author}
",
    ]
    try:
        result = subprocess.run(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=True,
        )
    except subprocess.CalledProcessError as exc:
        raise RuntimeError(f"Mercurial log command failed: {exc.stderr}") from None
    lines = result.stdout.strip().splitlines()
    if len(lines) < 3:
        raise ValueError("Incomplete log output received")
    return lines[0].strip(), lines[1].strip(), lines[2].strip()

