import hashlib
from pathlib import Path

def compute_sha256(apk_path, block_size=65536):
    if not isinstance(block_size, int) or block_size <= 0:
        raise ValueError("block_size must be a positive integer")
    if not isinstance(apk_path, (str, Path)):
        raise TypeError("apk_path must be a string or Path object")
    apk = Path(apk_path)
    if not apk.is_file():
        raise FileNotFoundError(f"APK file not found: {apk}")
    sha256 = hashlib.sha256()
    try:
        with apk.open("rb") as f:
            while True:
                chunk = f.read(block_size)
                if not chunk:
                    break
                sha256.update(chunk)
    except PermissionError as exc:
        raise PermissionError(f"Permission denied accessing APK: {apk}") from exc
    except OSError as exc:
        raise RuntimeError(f"Error reading APK file: {apk}") from exc
    return {"sha256": sha256.hexdigest()}

import ast
import traceback
import multiprocessing
import pickle
import sys

# Configuration
MAX_SNIPPET_LENGTH = 4096
MAX_RESULT_SIZE = 1024 * 1024  # 1 MB
ALLOWED_TYPES = (int, float, str, bool, list, tuple, dict, set)

def null_print(*_, **__):
    """Discarded print function."""
    pass

def _is_allowed(obj):
    """Recursively verify that obj is of an allowed type."""
    if isinstance(obj, ALLOWED_TYPES):
        if isinstance(obj, (list, tuple, set)):
            for item in obj:
                if not _is_allowed(item):
                    return False
            return True
        if isinstance(obj, dict):
            for key, value in obj.items():
                if not isinstance(key, (str, int)):
                    return False
                if not _is_allowed(value):
                    return False
            return True
        return True
    return False

def _eval_worker(queue, compiled_code, globals_, locals_):
    try:
        result = eval(compiled_code, globals_, locals_)
        if not _is_allowed(result):
            queue.put(("exc", ("TypeError", f"Disallowed return type: {type(result)}")))
            return
        try:
            pickled = pickle.dumps(result, protocol=pickle.HIGHEST_PROTOCOL)
        except Exception:
            queue.put(("exc", ("SerializationError", "Result not pickle-serializable")))
            return
        if len(pickled) > MAX_RESULT_SIZE:
            queue.put(("exc", ("MemoryError", "Result too large")))
            return
        queue.put(("ok", result))
    except Exception as e:
        queue.put(("exc", (type(e).__name__, str(e))))

def _evaluate_with_timeout(compiled_code, globals_, locals_, timeout_secs=5):
    queue = multiprocessing.Queue()
    proc = multiprocessing.Process(
        target=_eval_worker, args=(queue, compiled_code, globals_, locals_))
    proc.start()
    proc.join(timeout_secs)
    if proc.is_alive():
        proc.terminate()
        proc.join()
        raise TimeoutError(f"Evaluation exceeded {timeout_secs}s")
    if not queue.empty():
        status, payload = queue.get()
        if status == "ok":
            return payload
        else:
            exc_type, exc_msg = payload
            raise Exception(f"{exc_type}: {exc_msg}")
    raise RuntimeError("No result returned from evaluation process")

