import ast
import logging
from typing import Any, Union

_logger = logging.getLogger(__name__)

_OPERATOR_MAP = {
    ast.Add: lambda a, b: a + b,
    ast.Sub: lambda a, b: a - b,
    ast.Mult: lambda a, b: a * b,
    ast.Div: lambda a, b: a / b,
    ast.FloorDiv: lambda a, b: a // b,
    ast.Mod: lambda a, b: a % b,
    ast.Pow: lambda a, b: a ** b,
    ast.LShift: lambda a, b: a << b,
    ast.RShift: lambda a, b: a >> b,
    ast.BitOr: lambda a, b: a | b,
    ast.BitXor: lambda a, b: a ^ b,
    ast.BitAnd: lambda a, b: a & b,
    ast.UAdd: lambda a: a,
    ast.USub: lambda a: -a,
    ast.Not: lambda a: not a,
    ast.And: lambda a, b: a and b,
    ast.Or: lambda a, b: a or b,
    ast.Eq: lambda a, b: a == b,
    ast.NotEq: lambda a, b: a != b,
    ast.Lt: lambda a, b: a < b,
    ast.LtE: lambda a, b: a <= b,
    ast.Gt: lambda a, b: a > b,
    ast.GtE: lambda a, b: a >= b,
}


def _evaluate(node: ast.AST) -> Any:
    if isinstance(node, ast.Expression):
        return _evaluate(node.body)
    if isinstance(node, (ast.Constant,)):
        return node.value
    if isinstance(node, ast.Num):  # type: ignore[attr-defined]
        return node.n  # type: ignore[attr-defined]
    if isinstance(node, ast.Str):  # type: ignore[attr-defined]
        return node.s  # type: ignore[attr-defined]
    if isinstance(node, ast.Bytes):  # type: ignore[attr-defined]
        return node.s  # type: ignore[attr-defined]
    if isinstance(node, ast.NameConstant):
        return node.value
    if isinstance(node, ast.Tuple):
        return tuple(_evaluate(elt) for elt in node.elts)
    if isinstance(node, ast.List):
        return [_evaluate(elt) for elt in node.elts]
    if isinstance(node, ast.Set):
        return {_evaluate(elt) for elt in node.elts}
    if isinstance(node, ast.Dict):
        return {_evaluate(k): _evaluate(v) for k, v in zip(node.keys, node.values)}
    if isinstance(node, ast.BinOp):
        op_type = type(node.op)
        if op_type not in _OPERATOR_MAP:
            raise ValueError(f"Unsupported binary operator {op_type}")
        left = _evaluate(node.left)
        right = _evaluate(node.right)
        return _OPERATOR_MAP[op_type](left, right)
    if isinstance(node, ast.UnaryOp):
        op_type = type(node.op)
        if op_type not in _OPERATOR_MAP:
            raise ValueError(f"Unsupported unary operator {op_type}")
        operand = _evaluate(node.operand)
        return _OPERATOR_MAP[op_type](operand)
    if isinstance(node, ast.BoolOp):
        op_type = type(node.op)
        if op_type not in _OPERATOR_MAP:
            raise ValueError(f"Unsupported boolean operator {op_type}")
        values = [_evaluate(v) for v in node.values]
        result = values[0]
        for v in values[1:]:
            result = _OPERATOR_MAP[op_type](result, v)
        return result
    if isinstance(node, ast.Compare):
        left = _evaluate(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            op_type = type(op)
            if op_type not in _OPERATOR_MAP:
                raise ValueError(f"Unsupported comparison operator {op_type}")
            right = _evaluate(comparator)
            if not _OPERATOR_MAP[op_type](left, right):
                return False
            left = right
        return True
    raise ValueError(f"Disallowed AST node {type(node).__name__}")


