import json
import hashlib
import re
import secrets
import string

# Regular expression to allow alphanumeric characters and underscore
ALPHANUMERIC_RE = re.compile(r'^[A-Za-z0-9_]+$')

def safe_generate_key(length: int = 12) -> str:
    """
    Generate a cryptographically secure random key consisting of
    uppercase and lowercase letters and digits.
    """
    if not isinstance(length, int) or length <= 0:
        raise ValueError("Length must be a positive integer.")
    allowed_chars = string.ascii_letters + string.digits
    return ''.join(secrets.choice(allowed_chars) for _ in range(length))

def sanitize_dimensions(dims: dict) -> dict:
    """
    Retain only entries whose keys and values consist solely of
    alphanumeric characters or underscore.
    """
    sanitized = {}
    for key, value in dims.items():
        if not isinstance(key, str) or not isinstance(value, str):
            continue
        if ALPHANUMERIC_RE.match(key) and ALPHANUMERIC_RE.match(value):
            sanitized[key] = value
    return sanitized

# Generate and sanitize the dictionary containing the mold dimensions
MOLD_DIMENSIONS = sanitized_dimensions = sanitize_dimensions(
