def _check_depth(obj, max_depth=10):
    if max_depth < 0:
        raise ValueError("Configuration depth exceeds the allowed limit.")
    if isinstance(obj, dict):
        for v in obj.values():
            _check_depth(v, max_depth - 1)
    elif isinstance(obj, list):
