    return obj


def _validate_config(config):
    allowed_keys = {"database", "logging", "features", "security"}
    if not set(config).issubset(allowed_keys):
        raise ValueError("Configuration contains unexpected keys.")

    expected_schema = {
        "database": {"host": str, "port": int, "user": str, "password": str},
        "logging": {"level": str},
        "features": list,
        "security": {"enable_ssl": bool},
    }

    for key, value in config.items():
        schema = expected_schema[key]
        if isinstance(schema, dict):
            if not isinstance(value, dict):
                raise ValueError(f"The '{key}' section must be a mapping.")
            for subkey, subtype in schema.items():
                if subkey not in value:
                    raise ValueError(f"Missing required key '{subkey}' in '{key}'.")
                if not isinstance(value[subkey], subtype):
                    raise ValueError(
                        f"'{subkey}' in '{key}' must be of type {subtype.__name__}."
                    )
        elif isinstance(schema, type):
            if not isinstance(value, schema):
                raise ValueError(f"Value for '{key}' must be of type {schema.__name__}.")

    return _strip_strings(config)


def load_configuration(config_stream, config_file_path):
    try:
        config_dict = yaml.safe_load(config_stream)
        if config_dict is None:
            raise ValueError("Configuration file is empty.")
        if not isinstance(config_dict, dict):
            raise ValueError("Configuration file must contain a mapping.")
        _check_depth(config_dict, max_depth=10)
        config_dict = _validate_config(config_dict)
    except yaml.YAMLError as e:
        logger.error("Error parsing YAML configuration: %s", e)
        raise
    except (ValueError, KeyError) as e:
        logger.error("Configuration validation failed: %s", e)
        raise
    except RecursionError as e:
        logger.error("YAML configuration exceeds maximum depth: %s", e)
        raise ValueError("Configuration depth too deep.") from e
    except Exception as e:
        logger.error("Unexpected error reading configuration: %s", e)
        raise

    config_path = pathlib.Path(config_file_path).expanduser().resolve()
    if not str(config_path).startswith(str(CONFIG_DIR.resolve())):
        raise ValueError("Configuration file path is not within the allowed directory.")

    try:
        with config_path.open("w", encoding="utf-8") as out_stream:
            yaml.safe_dump(
                config_dict,
                out_stream,
                allow_unicode=True,
                default_flow_style=False,
            )
    except Exception as e:
        logger.error("Error writing configuration: %s", e)
        raise

    return config_dict

