        if not isinstance(website, str):
            raise ValueError("Website must be a string.")
        cleaned = website.strip()
        if not Helpers._website_pattern.fullmatch(cleaned):
            raise ValueError("Website contains invalid characters.")
        return cleaned

    @staticmethod
    def _validate_timestamp(timestamp: Union[int, float, str]) -> int:
        if isinstance(timestamp, (int, float)):
            ts = int(timestamp)
        elif isinstance(timestamp, str):
            ts = int(timestamp.strip())
        else:
            raise ValueError("Timestamp must be an integer or string representation of an integer.")
        if ts < 0 or ts > 2**63 - 1:
            raise ValueError("Timestamp out of bounds.")
        return ts

