def get_cache_name(prefix: str, name: Union[int, str]) -> str:
    """Return a safe cache key composed of prefix and name.
    The prefix must consist only of alphanumerics, underscores, and dots,
    be non-empty, and not exceed MAX_PREFIX_LENGTH characters.
    The name must be an integer or a string of digits and not exceed
    MAX_NAME_LENGTH characters when converted to a string."""
    if prefix is None or name is None:
        raise ValueError("prefix and name must not be None")
    if not isinstance(prefix, str):
        raise TypeError("prefix must be a string")
    if not prefix:
        raise ValueError("prefix must not be empty")
    if len(prefix) > MAX_PREFIX_LENGTH:
        raise ValueError(f"prefix exceeds maximum length of {MAX_PREFIX_LENGTH}")
    if not _PREFIX_REGEX.fullmatch(prefix):
        raise ValueError("prefix contains invalid characters")
    if isinstance(name, int):
        name_str = str(name)
    else:
        if not isinstance(name, str):
            raise TypeError("name must be an integer or a string of digits")
        if not name:
            raise ValueError("name must not be empty")
        if len(name) > MAX_NAME_LENGTH:
            raise ValueError(f"name exceeds maximum length of {MAX_NAME_LENGTH}")
        if not _NAME_REGEX.fullmatch(name):
            raise ValueError("name contains invalid characters")
        name_str = name
    return f'{prefix}.{name_str}'

