except Exception:
    logging.warning(f"Could not set permissions on {BASE_DIR}")

def is_within_safe_dir(target_path: str, base_dir: str = BASE_DIR) -> bool:
    """
    Return True if target_path is inside base_dir.
    Handles symlinks and intermediate traversal safely.
    """
    try:
        abs_target = os.path.realpath(target_path)
        abs_base = os.path.realpath(base_dir)
        if not abs_base or not abs_target:
            return False
        rel_path = os.path.relpath(abs_target, abs_base)
        # rel_path will start with '..' if abs_target is outside abs_base
        return not rel_path.startswith(os.pardir + os.sep) and rel_path != os.pardir
    except Exception:
        return False

def safe_remove(path: str, cleanup_list: list | None = None, verbose: bool = False) -> bool:
    """
    Safely remove a file or directory after validation.
    """
    if not is_within_safe_dir(path):
        raise ValueError(f"Unsafe path detected: {path}")

    if not os.path.exists(path):
        if verbose:
            logging.info(f"Path does not exist: {path}")
        return True

    # If the target is a symlink, remove the link only
    if os.path.islink(path):
        try:
            os.unlink(path)
            if verbose:
                logging.info(f"Removed symlink: {path}")
        except OSError as e:
            if verbose:
                logging.error(f"Failed to remove symlink {path}: {e}")
        return True

    # Attempt to remove the file or directory
    try:
        if os.path.isdir(path):
            shutil.rmtree(path, ignore_errors=False)
        else:
            os.remove(path)
    except OSError as e:
        if verbose:
            logging.error(f"Failed to remove {path}: {e}")
        return False

