def get_file_sha256(file_path: Union[str, pathlib.Path]) -> str:
    """
    Calculate the SHA-256 hash of a file while ensuring robust path resolution and
    comprehensive error handling.
    """
    if not isinstance(file_path, (str, pathlib.Path)):
        raise TypeError("file_path must be a string or pathlib.Path instance")

    try:
        path = pathlib.Path(file_path).expanduser().resolve(strict=True)
    except FileNotFoundError as exc:
        raise ValueError(f"Specified file does not exist: {file_path}") from exc
    except OSError as exc:
        raise RuntimeError(f"Unable to resolve path: {file_path}") from exc

    if not path.is_file():
        raise ValueError(f"Specified path is not a regular file: {file_path}")

    hash_func = hashlib.sha256()
    try:
        with path.open("rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                hash_func.update(chunk)
    except (PermissionError, OSError) as exc:
        raise RuntimeError(f"Unable to read file: {file_path}") from exc

    return hash_func.hexdigest()

