class CaseInsensitiveRFPDupeFilter(RFPDupeFilter):
    def request_fingerprint(self, request):
        try:
            url = getattr(request, "url", None)
            if not isinstance(url, str):
                raise ValueError("Invalid URL")
            parsed = urlparse(url)
            if not parsed.scheme or not parsed.netloc:
                raise ValueError("URL missing scheme or netloc")
            path = parsed.path.lower()
            query = parsed.query
            params = parse_qs(query, keep_blank_values=True)
            sorted_params = {k.lower(): sorted(v) for k, v in params.items()}
            canonical_query = urlencode(sorted_params, doseq=True)
            authority = f"{parsed.scheme.lower()}://{parsed.netloc.lower()}"
            fingerprint_payload = f"{authority}{path}"
            if canonical_query:
                fingerprint_payload += f"?{canonical_query}"
            return hashlib.sha256(fingerprint_payload.encode("utf-8")).hexdigest()
        except Exception as exc:
            logger.debug("Error generating fingerprint for request: %s", exc, exc_info=True)
            return None

