import logging
import types

# Global cache for hash method builders
_hash_method_cache = {}

_logger = logging.getLogger(__name__)

def _make_hash(attrs):
    """Return a hash method based on attribute descriptors."""
    if not isinstance(attrs, collections.abc.Iterable):
        raise TypeError("attrs must be an iterable of attribute descriptors")

    valid_attrs = []
    for a in attrs:
        if not hasattr(a, "hash"):
            raise AttributeError("Attribute descriptor missing 'hash' property")
        if a.hash not in (True, False, None):
            raise ValueError("Attribute 'hash' must be True, False, or None")
        if not hasattr(a, "cmp"):
            raise AttributeError("Attribute descriptor missing 'cmp' property")
        if not isinstance(a.cmp, bool):
            raise ValueError("Attribute 'cmp' must be a boolean")
        if not hasattr(a, "name"):
            raise AttributeError("Attribute descriptor missing 'name' property")
        if not isinstance(a.name, str):
            raise ValueError("Attribute 'name' must be a string")
        valid_attrs.append(a)

    attrs = tuple(
        a for a in valid_attrs
        if a.hash is True or (a.hash is None and a.cmp is True)
    )

    cache_key = tuple((a.name, a.hash, a.cmp) for a in attrs)
    if cache_key in _hash_method_cache:
        return _hash_method_cache[cache_key]

    def _convert(value):
        """Convert a value to a hashable form deterministically."""
        try:
            hash(value)
            return value
        except Exception:
            pass

        # Handle generators
        if isinstance(value, types.GeneratorType):
            return tuple(value)

        # Handle mappings
        if isinstance(value, collections.abc.Mapping):
            return tuple(sorted((k, _convert(v)) for k, v in value.items()))

        # Handle sets
        if isinstance(value, collections.abc.Set):
            return tuple(sorted(_convert(v) for v in value))

        # Handle other iterables (exclude strings, bytes, bytearray)
        if isinstance(value, collections.abc.Iterable) and not isinstance(value, (str, bytes, bytearray)):
            return tuple(_convert(v) for v in value)

        return None  # unhashable and cannot be converted

    def _hash(self):
        try:
            values = []
            for a in attrs:
                if not hasattr(self, a.name):
                    continue
                val = getattr(self, a.name)
                converted = _convert(val)
                if converted is None:
                    _logger.warning(f"Attribute {a.name!r} has unhashable value {val!r}; using sentinel.")
                    converted = 0
                values.append(converted)
            return hash(tuple(values))
        except Exception:
            _logger.exception("Error occurred during hash computation")
            return 0

    _hash_method_cache[cache_key] = _hash
    return _hash

