import tempfile
import requests
import socket
import ipaddress
from urllib.parse import urlparse
from typing import Tuple, List

MAX_BYTES = 100 * 1024 * 1024  # 100 MiB
SECURE_TREE = "SecureDownloader"
_TEMP_FILE_MODE = 0o600

def _is_internal_ip(hostname: str) -> bool:
    """Return True if any resolved IP of hostname is private, loopback, link-local, unspecified or a reserved IPv4 address."""
    try:
        addrinfo = socket.getaddrinfo(hostname, None)
    except socket.gaierror:
        return False  # dns resolution failure is treated as nonâinternal
    for entry in addrinfo:
        ip_str = entry[4][0]
        try:
            ip_obj = ipaddress.ip_address(ip_str)
        except ValueError:
            continue
        if (
            ip_obj.is_private
            or ip_obj.is_loopback
            or ip_obj.is_link_local
            or ip_obj.is_unspecified
            or ip_obj.is_reserved
        ):
            return True
    return False

def _validate_redirect_chain(history: List[requests.Response]) -> None:
    """Reject any redirect that points to an internal IP."""
    for resp in history:
        host = urlparse(resp.url).hostname
        if host and _is_internal_ip(host):
            raise ValueError("Redirect to internal address is not allowed")

def download_file(url: str) -> Tuple[str, str]:
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("Unsupported URL scheme; only http/https allowed")
    if not parsed.netloc:
        raise ValueError("URL must contain a network location")

    headers = {"User-Agent": f"{SECURE_TREE}/1.0"}
    timeout = (5, 30)

    temp_file = tempfile.NamedTemporaryFile(
        delete=False, mode="wb", prefix="download_", suffix=".tmp"
    )
    try:
        with requests.get(
            url,
            stream=True,
            headers=headers,
            timeout=timeout,
            allow_redirects=True,
        ) as response:
            response.raise_for_status()

            # Validate redirect chain
            _validate_redirect_chain(response.history)

            # Validate final destination does not point to private IPs
            final_host = urlparse(response.url).hostname
            if final_host and _is_internal_ip(final_host):
                raise ValueError("Internal addresses are not allowed")

            # Enforce content length if provided
            content_length = response.headers.get("Content-Length")
            if content_length is not None:
                try:
                    total = int(content_length)
                    if total > MAX_BYTES:
                        raise RuntimeError(
                            "File size exceeds maximum allowed limit"
                        )
                except ValueError:
                    pass  # malformed header is ignored for size enforcement

            sha256 = hashlib.sha256()
            bytes_downloaded = 0
            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    temp_file.write(chunk)
                    sha256.update(chunk)
                    bytes_downloaded += len(chunk)
                    if bytes_downloaded > MAX_BYTES:
                        raise RuntimeError(
                            "File size exceeds maximum allowed limit"
                        )
    except Exception as exc:
        temp_file.close()
        try:
            os.unlink(temp_file.name)
        finally:
            raise RuntimeError(f"Failed to download file: {exc}") from exc
    else:
        temp_file.close()
        os.chmod(temp_file.name, _TEMP_FILE_MODE)

    checksum = sha256.hexdigest()
    return temp_file.name, checksum

