import requests
from urllib.parse import urlparse
from typing import Dict

class SecureSubmissionError(Exception):
    """Raised when a secure submission fails."""


def submit_to_google(url: str, data: Dict) -> int:
    """
    Submit JSON data to a HTTPS endpoint using secure settings.
    Returns the HTTP status code on success.
    Raises SecureSubmissionError on validation or transmission failures.
    """
    if not isinstance(url, str):
        raise SecureSubmissionError("URL must be a string.")
    parsed = urlparse(url)
    if parsed.scheme.lower() != "https":
        raise SecureSubmissionError("URL must use HTTPS.")
    if not parsed.netloc:
        raise SecureSubmissionError("URL must have a valid network location.")
    if parsed.username or parsed.password:
        raise SecureSubmissionError("URL must not contain credentials.")

    if not isinstance(data, dict):
        raise SecureSubmissionError("Data must be a dictionary.")
    try:
        payload_json = json.dumps(data, separators=(',', ':'))
    except (TypeError, ValueError) as exc:
        raise SecureSubmissionError("Data must be JSON serializable.") from exc
    if len(payload_json.encode("utf-8")) > 1_048_576:
        raise SecureSubmissionError("Data payload exceeds 1 MB limit.")

    headers = {
        "Content-Type": "application/json",
        "User-Agent": "SecureClient/1.0",
        "Accept": "application/json",
    }
    timeout = (5, 10)  # connect timeout, read timeout

    try:
        with requests.Session() as session:
            session.headers.update(headers)
            response = session.post(
                url,
                data=payload_json,
                timeout=timeout,
                verify=True,
                allow_redirects=False,
            )
        if not 200 <= response.status_code < 300:
            raise SecureSubmissionError(
                f"Unexpected status code: {response.status_code}"
            )
        return response.status_code
    except requests.exceptions.RequestException as exc:
        raise SecureSubmissionError("Failed to submit data securely.") from exc

