import json
import logging

class ResponseValidator:
    def __init__(self, logger=None):
        self.logger = logger or logging.getLogger(__name__)

    def validate(self, rv, type_to_update):
        self._assert_status(rv)
        payload = self._parse_payload(rv)
        self._assert_payload_structure(payload)
        self._assert_name_match(payload, type_to_update)
        self._log_sanitized(payload)

    def _assert_status(self, rv):
        if rv.status_code != 200:
            raise AssertionError(f'Unexpected status code: {rv.status_code}')

    def _parse_payload(self, rv):
        try:
            data = rv.get_data(as_text=True)
            payload = json.loads(data)
        except (ValueError, json.JSONDecodeError) as e:
            raise AssertionError(f'JSON decode error: {e}')
        return payload

    def _assert_payload_structure(self, payload):
        if not isinstance(payload, dict):
            raise AssertionError('Response payload must be a dictionary')
        required_keys = {'id', 'theName', 'description', 'created_at', 'updated_at'}
        missing = required_keys - payload.keys()
        if missing:
            raise AssertionError(f'Missing keys in response: {missing}')

    def _assert_name_match(self, payload, type_to_update):
        if payload.get('theName') != type_to_update.theName:
            raise AssertionError(
                f'Expected theName {type_to_update.theName} but got {payload.get("theName")}'
            )

    def _log_sanitized(self, payload):
        sanitized = {
            k: v if k not in ('created_at', 'updated_at') else '[REDACTED]'
            for k, v in payload.items()
        }
        self.logger.debug('Sanitized payload: %s', sanitized)

