        raise ValueError("Query must be a string")
    query = query.strip()
    if not query:
        raise ValueError("Query cannot be empty")
    if len(query) > 200:
        raise ValueError("Query is too long")
    allowed = set("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 -_'")
