import hashlib
import base64

logger = logging.getLogger(__name__)

class SecureAuth:
    def __init__(self, key: str, realm: str) -> None:
        if not isinstance(key, str):
            raise ValueError("key must be a string.")
        if not isinstance(realm, str):
            raise ValueError("realm must be a string.")
        secret = os.getenv("HMAC_SECRET_KEY")
        if not secret or not isinstance(secret, str):
            raise RuntimeError("HMAC_SECRET_KEY environment variable must be set and non-empty.")
        self.key = key
        self.realm = realm
        self._secret = secret

    def generate_signature(self, nonce: str) -> str:
        """
        Generate a base64-encoded HMACâSHA256 signature for the given nonce.
        The nonce must be a numeric string.
        """
        if not isinstance(nonce, str) or not nonce.isdigit():
            raise ValueError("Nonce must be a numeric string.")

        message = f"{self.key}:{self.realm}:{nonce}".encode("utf-8")
        try:
            digest = hmac.new(
                self._secret.encode("utf-8"),
                message,
                hashlib.sha256
            ).digest()
        except Exception as exc:
            logger.error("Failed to compute signature: %s", exc)
            raise RuntimeError("Signature computation failed") from None

        signature = base64.b64encode(digest).decode("ascii")
        self._signature = signature
        return signature

    @property
    def signature(self) -> str | None:
        """Return the last generated signature, if any."""
        return getattr(self, "_signature", None)

