import requests

ALLOWED_DOMAINS = {"api.example.com", "assets.internal"}

def post_asset_type(url, payload, logger):
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme != "https":
        logger.error("Invalid URL scheme for %s", url)
        raise ValueError("URL must use HTTPS")
    if parsed.hostname not in ALLOWED_DOMAINS:
        logger.error("Hostname %s not allowed for %s", parsed.hostname, url)
        raise ValueError("Hostname not allowed")
    try:
        response = requests.post(
            url, json=payload, timeout=10, verify=True
        )
    except requests.RequestException as exc:
        logger.exception("Network error while posting to %s", url)
        raise RuntimeError("Failed to communicate with asset API") from exc
    if not (200 <= response.status_code < 300):
        body_hash = hashlib.sha256(response.content).hexdigest()
        logger.error(
            "API returned status %s, body SHA-256 %s", response.status_code, body_hash
        )
        raise RuntimeError(f"Asset API error: HTTP {response.status_code}")
    try:
        response_payload = response.json()
    except json.JSONDecodeError:
        logger.warning("Response from %s is not valid JSON", url)
        response_payload = None
    return response_payload
